SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Energy losses in a transformer can be reduced by:", "explanation": "Major transformer losses include: (1) Eddy current losses — reduced by using laminated iron core, (2) Hysteresis losses — reduced by using soft iron (low coercivity), (3) Copper losses (I²R) — reduced by using thick copper wires, (4) Flux leakage — reduced by winding coils over each other.", "correct_answer": "D", "concept_tags": ["transformer", "energy-losses", "lamination"], "payload": {"question_id": "cuet-phy-ac-circuits-35", "subtopic": "transformer losses", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "Using a solid iron core", "is_correct": false}, {"key": "B", "value": "Using thin wires for windings", "is_correct": false}, {"key": "C", "value": "Keeping primary and secondary coils far apart", "is_correct": false}, {"key": "D", "value": "Using a laminated soft iron core with thick copper windings", "is_correct": true}], "elimination_hints": ["Solid iron cores have large eddy currents — lamination reduces them.", "Thin wires have high resistance, increasing I²R (copper) losses.", "Keeping coils far apart increases flux leakage — they should be close together."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A series LCR circuit has R = 20 Ω, L = 0.2 H, C = 50 μF and is connected to a 220 V, 50 Hz source. The current in the circuit is approximately:", "explanation": "X_L = 2πfL = 2π × 50 × 0.2 = 20π ≈ 62.8 Ω. X_C = 1/(2πfC) = 1/(2π × 50 × 50 × 10⁻⁶) = 1/(5π × 10⁻³) = 200/π ≈ 63.7 Ω. X_L − X_C ≈ 62.8 − 63.7 = −0.9 Ω. Z = √(20² + 0.81) ≈ √(400.81) ≈ 20.02 Ω. I = V/Z = 220/20.02 ≈ 11 A.", "correct_answer": "C", "concept_tags": ["LCR-circuit", "impedance", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-36", "subtopic": "series LCR circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "2.5 A", "is_correct": false}, {"key": "B", "value": "5 A", "is_correct": false}, {"key": "C", "value": "11 A", "is_correct": true}, {"key": "D", "value": "22 A", "is_correct": false}], "elimination_hints": ["X_L ≈ X_C ≈ 63 Ω, so they nearly cancel — the circuit is near resonance.", "Near resonance, Z ≈ R = 20 Ω, so I ≈ 220/20 = 11 A.", "22 A would imply Z ≈ 10 Ω, which is less than R alone — impossible."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a series LCR circuit, if X_L > X_C, the circuit is:", "explanation": "When X_L > X_C, the net reactance is inductive (positive). The current lags behind the voltage. The phase angle φ = tan⁻¹[(X_L − X_C)/R] is positive, meaning the circuit behaves inductively.", "correct_answer": "A", "concept_tags": ["LCR-circuit", "inductive-behavior", "phase-angle"], "payload": {"question_id": "cuet-phy-ac-circuits-37", "subtopic": "series LCR circuit", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "Inductive (current lags voltage)", "is_correct": true}, {"key": "B", "value": "Capacitive (current leads voltage)", "is_correct": false}, {"key": "C", "value": "Resistive (current in phase with voltage)", "is_correct": false}, {"key": "D", "value": "At resonance", "is_correct": false}], "elimination_hints": ["X_L > X_C means inductive reactance dominates — the circuit behaves like an inductor.", "Capacitive behavior requires X_C > X_L.", "At resonance, X_L = X_C exactly."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A transformer cannot work with DC because:", "explanation": "A transformer requires changing magnetic flux to induce EMF in the secondary (Faraday''s law). DC produces a constant current, hence a constant magnetic flux, so dΦ/dt = 0 and no EMF is induced in the secondary. Additionally, DC can saturate the core.", "correct_answer": "B", "concept_tags": ["transformer", "DC-limitation", "flux-change"], "payload": {"question_id": "cuet-phy-ac-circuits-38", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "DC produces too much current", "is_correct": false}, {"key": "B", "value": "DC produces a constant flux which does not induce EMF in the secondary", "is_correct": true}, {"key": "C", "value": "DC cannot flow through the primary coil", "is_correct": false}, {"key": "D", "value": "DC destroys the core material", "is_correct": false}], "elimination_hints": ["DC can certainly flow through the primary coil (it''s just a wire).", "The problem is not the amount of current but the lack of changing flux.", "Faraday''s law: ε = −dΦ/dt. If Φ is constant (DC), ε = 0 in the secondary."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In long-distance power transmission, electrical energy is transmitted at high voltage and low current because:", "explanation": "Power loss in transmission lines = I²R, where R is the line resistance. By using high voltage (via step-up transformer), the current is reduced for the same power (P = VI). Lower current means much less I²R power loss. At the receiving end, a step-down transformer reduces the voltage for consumer use.", "correct_answer": "D", "concept_tags": ["power-transmission", "high-voltage", "I²R-losses"], "payload": {"question_id": "cuet-phy-ac-circuits-39", "subtopic": "power transmission", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "High voltage is safer for transmission", "is_correct": false}, {"key": "B", "value": "High voltage reduces the cost of cables", "is_correct": false}, {"key": "C", "value": "Low current increases the power delivered", "is_correct": false}, {"key": "D", "value": "Low current reduces I²R transmission losses", "is_correct": true}], "elimination_hints": ["High voltage is actually more dangerous, not safer.", "Power delivered P = VI remains the same; only the losses change.", "Transmission losses depend on I²R — reducing I drastically reduces losses."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An AC source of 220 V, 50 Hz is connected to a series combination of a 10 Ω resistance and a capacitor of 100/(π) μF. The power dissipated in the circuit is:", "explanation": "X_C = 1/(2πfC) = 1/(2π × 50 × 100/(π) × 10⁻⁶) = 1/(2 × 50 × 100 × 10⁻⁶) = 1/(10⁻² ) = 100 Ω. Z = √(R² + X_C²) = √(100 + 10000) = √10100 ≈ 100.5 Ω. I_rms = 220/100.5 ≈ 2.19 A. Power = I²R = (2.19)² × 10 ≈ 48 W. Alternatively, P = V²R/Z² = 220² × 10/10100 ≈ 484000/10100 ≈ 48 W.", "correct_answer": "B", "concept_tags": ["RC-circuit", "power-dissipation", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-40", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "24 W", "is_correct": false}, {"key": "B", "value": "48 W", "is_correct": true}, {"key": "C", "value": "484 W", "is_correct": false}, {"key": "D", "value": "4840 W", "is_correct": false}], "elimination_hints": ["X_C = 100 Ω (much larger than R = 10 Ω), so Z ≈ 100.5 Ω.", "484 W = V²/R — this ignores the capacitive reactance entirely.", "P = V²R/Z² = (220)² × 10 / (100.5)² ≈ 48 W."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In an LC oscillating circuit, the total energy is:", "explanation": "In an ideal LC circuit, energy oscillates between the inductor (magnetic energy ½LI²) and the capacitor (electric energy ½CV²). The total energy remains constant as there is no resistance to dissipate energy. At any instant, U_total = ½LI² + ½CV² = ½CV₀² = ½LI₀² = constant.", "correct_answer": "C", "concept_tags": ["LC-oscillation", "energy-conservation", "electromagnetic-oscillation"], "payload": {"question_id": "cuet-phy-ac-adv-01", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "Stored only in the inductor", "is_correct": false}, {"key": "B", "value": "Stored only in the capacitor", "is_correct": false}, {"key": "C", "value": "Constant and shared between L and C", "is_correct": true}, {"key": "D", "value": "Continuously dissipated as heat", "is_correct": false}], "elimination_hints": ["Energy is stored in the inductor only at the instant of maximum current.", "Energy is stored in the capacitor only at the instant of maximum charge.", "There is no resistance in an ideal LC circuit, so no heat is dissipated."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The frequency of oscillation in an ideal LC circuit with inductance L and capacitance C is:", "explanation": "The angular frequency of LC oscillation is ω = 1/√(LC), so the frequency f = ω/(2π) = 1/(2π√(LC)). This is analogous to SHM of a spring-mass system where ω = √(k/m).", "correct_answer": "B", "concept_tags": ["LC-oscillation", "frequency", "angular-frequency"], "payload": {"question_id": "cuet-phy-ac-adv-02", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "1/(2π)√(L/C)", "is_correct": false}, {"key": "B", "value": "1/(2π√(LC))", "is_correct": true}, {"key": "C", "value": "2π√(LC)", "is_correct": false}, {"key": "D", "value": "1/(2πLC)", "is_correct": false}], "elimination_hints": ["√(L/C) has dimensions of impedance, not frequency.", "2π√(LC) has dimensions of time (the time period T), not frequency.", "1/(2πLC) does not have the correct dimensions of frequency."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LC circuit, the charge on the capacitor oscillates as q = q₀ cos(ωt). The current in the circuit is:", "explanation": "Current I = dq/dt = d(q₀ cos(ωt))/dt = −q₀ω sin(ωt). The magnitude of maximum current I₀ = q₀ω. The current leads the charge by π/2 (90°). When charge is maximum, current is zero and vice versa.", "correct_answer": "A", "concept_tags": ["LC-oscillation", "current", "differentiation", "phase"], "payload": {"question_id": "cuet-phy-ac-adv-03", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "−q₀ω sin(ωt)", "is_correct": true}, {"key": "B", "value": "q₀ω sin(ωt)", "is_correct": false}, {"key": "C", "value": "q₀ω cos(ωt)", "is_correct": false}, {"key": "D", "value": "−q₀ω cos(ωt)", "is_correct": false}], "elimination_hints": ["Current is the derivative of charge, not the same function.", "d(cos(ωt))/dt = −ω sin(ωt), so the negative sign is essential.", "cos differentiates to −sin, not to cos or +sin."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The LC oscillation is analogous to the mechanical oscillation of a spring-mass system. In this analogy, the inductance L corresponds to:", "explanation": "In the LC-SHM analogy: inductance L ↔ mass m, capacitance C ↔ 1/k (inverse of spring constant), charge q ↔ displacement x, current I ↔ velocity v, ½LI² ↔ ½mv² (kinetic energy), ½q²/C ↔ ½kx² (potential energy).", "correct_answer": "B", "concept_tags": ["LC-oscillation", "SHM-analogy", "inductance"], "payload": {"question_id": "cuet-phy-ac-adv-04", "subtopic": "LC oscillations — SHM analogy", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Spring constant k", "is_correct": false}, {"key": "B", "value": "Mass m", "is_correct": true}, {"key": "C", "value": "Displacement x", "is_correct": false}, {"key": "D", "value": "Velocity v", "is_correct": false}], "elimination_hints": ["Spring constant k corresponds to 1/C, not L.", "Displacement x corresponds to charge q.", "L appears in ½LI² which is analogous to ½mv², so L ↔ m."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LC oscillating circuit with inductance L = 0.5 H and capacitance C = 20 μF, the angular frequency of oscillation is:", "explanation": "ω = 1/√(LC) = 1/√(0.5 × 20 × 10⁻⁶) = 1/√(10⁻⁵) = 1/(10⁻²·⁵) = 10²·⁵ = √(10⁵) = √(100000) ≈ 316.2 rad/s. Rounding: ω = 100√10 ≈ 316 rad/s.", "correct_answer": "C", "concept_tags": ["LC-oscillation", "angular-frequency", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-05", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "100 rad/s", "is_correct": false}, {"key": "B", "value": "200 rad/s", "is_correct": false}, {"key": "C", "value": "100√10 rad/s", "is_correct": true}, {"key": "D", "value": "1000 rad/s", "is_correct": false}], "elimination_hints": ["LC = 0.5 × 20 × 10⁻⁶ = 10⁻⁵, so √(LC) = 10⁻²·⁵.", "1/10⁻²·⁵ = 10²·⁵ = √(10⁵) = 100√10 ≈ 316 rad/s.", "100 rad/s and 1000 rad/s are common traps from unit errors."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "When the current in an LC circuit is maximum, the energy stored in the inductor is:", "explanation": "When current is maximum (I = I₀), all energy is stored in the inductor as magnetic energy: U_L = ½LI₀². At this instant the capacitor is fully discharged (q = 0), so U_C = 0. The total energy equals ½LI₀².", "correct_answer": "D", "concept_tags": ["LC-oscillation", "magnetic-energy", "energy-transfer"], "payload": {"question_id": "cuet-phy-ac-adv-06", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Zero", "is_correct": false}, {"key": "B", "value": "Half of the total energy", "is_correct": false}, {"key": "C", "value": "One-fourth of the total energy", "is_correct": false}, {"key": "D", "value": "Equal to the total energy", "is_correct": true}], "elimination_hints": ["Zero energy in the inductor occurs when current is zero, not maximum.", "Energy is equally shared when I = I₀/√2, not at maximum current.", "At maximum current, the capacitor is fully discharged — all energy is in L."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The power factor of a purely resistive AC circuit is:", "explanation": "Power factor = cos φ, where φ is the phase difference between voltage and current. In a purely resistive circuit, voltage and current are in phase (φ = 0°), so cos 0° = 1. Maximum power is dissipated.", "correct_answer": "A", "concept_tags": ["power-factor", "resistive-circuit", "phase-angle"], "payload": {"question_id": "cuet-phy-ac-adv-07", "subtopic": "power factor", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "1", "is_correct": true}, {"key": "B", "value": "0", "is_correct": false}, {"key": "C", "value": "0.5", "is_correct": false}, {"key": "D", "value": "∞", "is_correct": false}], "elimination_hints": ["Power factor = 0 for purely reactive (L or C) circuits, not resistive.", "cos φ always lies between 0 and 1; it cannot be ∞.", "In a purely resistive circuit, φ = 0° and cos 0° = 1."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The wattless component of current in an AC circuit is:", "explanation": "In an AC circuit, the current has two components: (1) I cos φ — the active or wattful component (in phase with voltage, responsible for power dissipation), and (2) I sin φ — the reactive or wattless component (90° out of phase with voltage, contributes zero average power).", "correct_answer": "B", "concept_tags": ["wattless-current", "reactive-component", "power-factor"], "payload": {"question_id": "cuet-phy-ac-adv-08", "subtopic": "wattless current", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "I cos φ", "is_correct": false}, {"key": "B", "value": "I sin φ", "is_correct": true}, {"key": "C", "value": "I tan φ", "is_correct": false}, {"key": "D", "value": "I/cos φ", "is_correct": false}], "elimination_hints": ["I cos φ is the wattful (active) component, not the wattless component.", "I tan φ and I/cos φ do not represent standard AC current components.", "The wattless component is perpendicular to voltage — it involves sin φ."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a purely inductive AC circuit, the wattless component of current is:", "explanation": "In a purely inductive circuit, the phase angle φ = 90° (current lags voltage by π/2). The wattless component = I sin φ = I sin 90° = I (the entire current). The active component = I cos 90° = 0. Hence no power is dissipated — all current is wattless.", "correct_answer": "C", "concept_tags": ["wattless-current", "inductive-circuit", "phase-angle"], "payload": {"question_id": "cuet-phy-ac-adv-09", "subtopic": "wattless current", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "Zero", "is_correct": false}, {"key": "B", "value": "I/√2", "is_correct": false}, {"key": "C", "value": "I (total current)", "is_correct": true}, {"key": "D", "value": "I/2", "is_correct": false}], "elimination_hints": ["Zero wattless current occurs in a purely resistive circuit (φ = 0).", "I/√2 would occur when φ = 45°, not 90°.", "For purely inductive circuit φ = 90°, so sin 90° = 1 → entire current is wattless."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An AC circuit has an impedance of 50 Ω and the voltage leads the current by 60°. The wattful and wattless components of a 4 A current are:", "explanation": "Wattful component = I cos φ = 4 × cos 60° = 4 × 0.5 = 2 A. Wattless component = I sin φ = 4 × sin 60° = 4 × (√3/2) = 2√3 A. The power dissipated = V_rms × I × cos φ = 50 × 4 × 4 × 0.5 = 400 W (or equivalently I²R where R = Z cos φ = 25 Ω).", "correct_answer": "B", "concept_tags": ["wattless-current", "wattful-current", "numerical", "impedance"], "payload": {"question_id": "cuet-phy-ac-adv-10", "subtopic": "wattless current", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "2√3 A and 2 A", "is_correct": false}, {"key": "B", "value": "2 A and 2√3 A", "is_correct": true}, {"key": "C", "value": "4 A and 0 A", "is_correct": false}, {"key": "D", "value": "0 A and 4 A", "is_correct": false}], "elimination_hints": ["Option A swaps the wattful and wattless values.", "4 A and 0 A would mean φ = 0° (purely resistive), but φ = 60°.", "cos 60° = 0.5, so wattful = 4 × 0.5 = 2 A; sin 60° = √3/2, so wattless = 2√3 A."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The power dissipated in a purely capacitive AC circuit is:", "explanation": "In a purely capacitive circuit, the phase angle φ = 90° (current leads voltage by π/2). Average power P = V_rms × I_rms × cos φ = V_rms × I_rms × cos 90° = 0. Energy is alternately stored in and returned from the capacitor''s electric field.", "correct_answer": "A", "concept_tags": ["power", "capacitive-circuit", "wattless"], "payload": {"question_id": "cuet-phy-ac-adv-11", "subtopic": "power in reactive circuits", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "Zero", "is_correct": true}, {"key": "B", "value": "V_rms × I_rms", "is_correct": false}, {"key": "C", "value": "½ V_rms × I_rms", "is_correct": false}, {"key": "D", "value": "V_rms²/X_C", "is_correct": false}], "elimination_hints": ["V_rms × I_rms is the apparent power, not the true (real) power.", "V_rms²/X_C gives the reactive power (VAR), not the real power (W).", "cos 90° = 0, so no real power is dissipated in a purely capacitive circuit."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The quality factor (Q-factor) of a series LCR circuit at resonance is given by:", "explanation": "Q-factor = ω₀L/R = 1/(ω₀CR) = (1/R)√(L/C). It measures the sharpness of resonance — a higher Q means a narrower resonance peak. Q also equals the ratio of voltage across L (or C) to the applied voltage at resonance.", "correct_answer": "D", "concept_tags": ["Q-factor", "resonance", "LCR-circuit", "sharpness"], "payload": {"question_id": "cuet-phy-ac-adv-12", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "R/(ω₀L)", "is_correct": false}, {"key": "B", "value": "ω₀CR", "is_correct": false}, {"key": "C", "value": "R√(L/C)", "is_correct": false}, {"key": "D", "value": "(1/R)√(L/C)", "is_correct": true}], "elimination_hints": ["R/(ω₀L) is 1/Q, the inverse of the quality factor.", "ω₀CR is also 1/Q — inverting the correct formula.", "Q = ω₀L/R = (1/R)√(L/C). Higher L/C ratio and lower R give higher Q."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A series LCR circuit has L = 10 mH, C = 1 μF, and R = 10 Ω at resonance. The Q-factor of the circuit is:", "explanation": "Q = (1/R)√(L/C) = (1/10)√(10 × 10⁻³/(1 × 10⁻⁶)) = (1/10)√(10⁴) = (1/10) × 100 = 10. Alternatively, ω₀ = 1/√(LC) = 1/√(10⁻⁸) = 10⁴ rad/s, and Q = ω₀L/R = 10⁴ × 10⁻² / 10 = 10.", "correct_answer": "C", "concept_tags": ["Q-factor", "numerical", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-adv-13", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "1", "is_correct": false}, {"key": "B", "value": "5", "is_correct": false}, {"key": "C", "value": "10", "is_correct": true}, {"key": "D", "value": "100", "is_correct": false}], "elimination_hints": ["√(L/C) = √(10⁻²/10⁻⁶) = √(10⁴) = 100.", "Q = 100/R = 100/10 = 10.", "100 would be the voltage magnification factor times R, not Q itself."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The bandwidth (Δω) of a series LCR resonant circuit is given by:", "explanation": "Bandwidth Δω = R/L. It is the range of angular frequencies around resonance for which the power is at least half the maximum power (half-power points). A higher Q-factor means smaller bandwidth: Δω = ω₀/Q = R/L.", "correct_answer": "A", "concept_tags": ["bandwidth", "resonance", "LCR-circuit", "half-power"], "payload": {"question_id": "cuet-phy-ac-adv-14", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "R/L", "is_correct": true}, {"key": "B", "value": "L/R", "is_correct": false}, {"key": "C", "value": "1/√(LC)", "is_correct": false}, {"key": "D", "value": "R/C", "is_correct": false}], "elimination_hints": ["L/R is the time constant of an LR circuit, not bandwidth.", "1/√(LC) is the resonant frequency ω₀, not the bandwidth.", "Bandwidth = ω₀/Q = (1/√(LC))/(ω₀L/R) = R/L."]}}]'::jsonb, 'deploy-2026-03-05-b07');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a series LCR circuit, L = 0.1 H, C = 10 μF, and R = 20 Ω. The bandwidth and Q-factor of the circuit are:", "explanation": "Bandwidth Δω = R/L = 20/0.1 = 200 rad/s. Resonant frequency ω₀ = 1/√(LC) = 1/√(0.1 × 10 × 10⁻⁶) = 1/√(10⁻⁶) = 1000 rad/s. Q = ω₀/Δω = 1000/200 = 5. Alternatively, Q = ω₀L/R = 1000 × 0.1/20 = 5.", "correct_answer": "B", "concept_tags": ["bandwidth", "Q-factor", "numerical", "resonance"], "payload": {"question_id": "cuet-phy-ac-adv-15", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "100 rad/s and 10", "is_correct": false}, {"key": "B", "value": "200 rad/s and 5", "is_correct": true}, {"key": "C", "value": "200 rad/s and 10", "is_correct": false}, {"key": "D", "value": "500 rad/s and 2", "is_correct": false}], "elimination_hints": ["Δω = R/L = 20/0.1 = 200, so options with 100 or 500 are wrong.", "Q = ω₀L/R = 1000 × 0.1 / 20 = 5.", "Options with Q = 10 use ω₀ = 1000 but divide by R = 100 (wrong R)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "At resonance in a series LCR circuit, the voltage across the capacitor is Q times the applied voltage. If Q = 20 and the applied RMS voltage is 10 V, the voltage across the capacitor is:", "explanation": "At resonance, V_C = Q × V_applied = 20 × 10 = 200 V. This is because at resonance, X_L = X_C, and the current I = V/R. Voltage across C = IX_C = (V/R)(ω₀L) = V × (ω₀L/R) = VQ. The voltage across L also equals 200 V, and V_L and V_C cancel each other.", "correct_answer": "D", "concept_tags": ["Q-factor", "voltage-magnification", "resonance", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-16", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "10 V", "is_correct": false}, {"key": "B", "value": "20 V", "is_correct": false}, {"key": "C", "value": "100 V", "is_correct": false}, {"key": "D", "value": "200 V", "is_correct": true}], "elimination_hints": ["10 V is the applied voltage, not the amplified voltage across C.", "Q-factor acts as a voltage amplification factor at resonance.", "V_C = Q × V = 20 × 10 = 200 V."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The average power consumed in an AC circuit is given by:", "explanation": "Average power P = V_rms × I_rms × cos φ, where cos φ is the power factor. This is also written as P = I²_rms × R. The term V_rms × I_rms is the apparent power, and cos φ converts it to the actual (real) power dissipated.", "correct_answer": "C", "concept_tags": ["average-power", "power-factor", "real-power"], "payload": {"question_id": "cuet-phy-ac-adv-17", "subtopic": "power in AC circuits", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "V_rms × I_rms", "is_correct": false}, {"key": "B", "value": "V_rms × I_rms × sin φ", "is_correct": false}, {"key": "C", "value": "V_rms × I_rms × cos φ", "is_correct": true}, {"key": "D", "value": "V_rms × I_rms × tan φ", "is_correct": false}], "elimination_hints": ["V_rms × I_rms is the apparent power (VA), not the real power (W).", "sin φ gives the reactive component, not the power-dissipating component.", "Only the in-phase component (cos φ) contributes to real power dissipation."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The power factor of a series LCR circuit at resonance is:", "explanation": "At resonance, X_L = X_C, so the net reactance is zero. The impedance Z = R (purely resistive). The phase angle φ = tan⁻¹((X_L − X_C)/R) = tan⁻¹(0) = 0°. Therefore, power factor = cos 0° = 1. Maximum power is transferred at resonance.", "correct_answer": "A", "concept_tags": ["power-factor", "resonance", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-adv-18", "subtopic": "power factor", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "1", "is_correct": true}, {"key": "B", "value": "0", "is_correct": false}, {"key": "C", "value": "0.5", "is_correct": false}, {"key": "D", "value": "1/√2", "is_correct": false}], "elimination_hints": ["Power factor = 0 in purely reactive circuits, not at resonance.", "At resonance the circuit is purely resistive — φ = 0° → cos φ = 1.", "Power factor = 1 means maximum power transfer."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A power station delivers 500 kW of power at 10,000 V to a factory through cables of total resistance 4 Ω. The power loss in transmission is:", "explanation": "Current I = P/V = 500 × 10³/10⁴ = 50 A. Power loss = I²R = 50² × 4 = 2500 × 4 = 10,000 W = 10 kW. The percentage loss = (10/500) × 100 = 2%. This shows why high-voltage transmission reduces losses — the current is smaller for the same power.", "correct_answer": "B", "concept_tags": ["power-transmission", "transmission-loss", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-19", "subtopic": "power transmission", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "5 kW", "is_correct": false}, {"key": "B", "value": "10 kW", "is_correct": true}, {"key": "C", "value": "20 kW", "is_correct": false}, {"key": "D", "value": "50 kW", "is_correct": false}], "elimination_hints": ["I = P/V = 500000/10000 = 50 A.", "Power loss = I²R = 2500 × 4 = 10000 W = 10 kW.", "50 kW would require I²R = 50000, which doesn''t match these values."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the transmission voltage is doubled, the power loss in the cables becomes:", "explanation": "Power loss = I²R = (P/V)²R = P²R/V². If V is doubled, loss becomes P²R/(2V)² = P²R/(4V²) = original loss/4. So doubling the voltage reduces the power loss to one-fourth. This is the key reason for high-voltage power transmission.", "correct_answer": "B", "concept_tags": ["power-transmission", "voltage", "efficiency"], "payload": {"question_id": "cuet-phy-ac-adv-20", "subtopic": "power transmission", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "Half of the original", "is_correct": false}, {"key": "B", "value": "One-fourth of the original", "is_correct": true}, {"key": "C", "value": "Double the original", "is_correct": false}, {"key": "D", "value": "Same as the original", "is_correct": false}], "elimination_hints": ["Loss ∝ 1/V², so doubling V reduces loss by a factor of 4.", "Half would be correct if loss ∝ 1/V, but it''s ∝ 1/V².", "Higher voltage means lower current for same power → much less I²R loss."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The efficiency of a transformer is defined as:", "explanation": "Efficiency η = (output power / input power) × 100%. For an ideal transformer η = 100%. Real transformers have η between 90–99% due to copper losses, eddy current losses, hysteresis losses, and flux leakage.", "correct_answer": "A", "concept_tags": ["transformer", "efficiency", "power"], "payload": {"question_id": "cuet-phy-ac-adv-21", "subtopic": "transformer efficiency", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "(Output power / Input power) × 100%", "is_correct": true}, {"key": "B", "value": "(Input power / Output power) × 100%", "is_correct": false}, {"key": "C", "value": "(V_s / V_p) × 100%", "is_correct": false}, {"key": "D", "value": "(N_p / N_s) × 100%", "is_correct": false}], "elimination_hints": ["Input/Output ratio would give a value > 100% for a real transformer.", "V_s/V_p is the voltage ratio (turns ratio), not efficiency.", "Efficiency relates power output to power input, not voltages or turns."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Copper loss (I²R loss) in a transformer is due to:", "explanation": "Copper loss occurs because the primary and secondary windings have finite resistance. When current flows through these windings, energy is dissipated as heat (I²R). It can be reduced by using thick copper wires (low resistance).", "correct_answer": "C", "concept_tags": ["transformer", "copper-loss", "resistance", "heating"], "payload": {"question_id": "cuet-phy-ac-adv-22", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "Eddy currents in the core", "is_correct": false}, {"key": "B", "value": "Hysteresis in the core", "is_correct": false}, {"key": "C", "value": "Resistance of the windings", "is_correct": true}, {"key": "D", "value": "Magnetic flux leakage", "is_correct": false}], "elimination_hints": ["Eddy currents cause iron loss, not copper loss.", "Hysteresis loss is due to repeated magnetization of the core.", "Copper loss = I²R, and R is the resistance of the copper windings."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Eddy current losses in a transformer core are minimized by:", "explanation": "Eddy currents are induced in the transformer core by the changing magnetic flux. Using a laminated core (thin insulated sheets) increases the resistance to eddy current paths, confining them to small loops within each lamination, thereby reducing I²R heating.", "correct_answer": "B", "concept_tags": ["transformer", "eddy-current-loss", "lamination"], "payload": {"question_id": "cuet-phy-ac-adv-23", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Using thick copper windings", "is_correct": false}, {"key": "B", "value": "Using a laminated iron core", "is_correct": true}, {"key": "C", "value": "Increasing the frequency", "is_correct": false}, {"key": "D", "value": "Using a solid iron core", "is_correct": false}], "elimination_hints": ["Thick copper windings reduce copper loss, not eddy current loss.", "Increasing frequency actually increases eddy current losses.", "A solid core allows large eddy current loops — lamination breaks them up."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Hysteresis loss in a transformer can be minimized by using a core material with:", "explanation": "Hysteresis loss is proportional to the area of the B-H (hysteresis) loop. Soft magnetic materials like soft iron or silicon steel have narrow hysteresis loops (low coercivity and low retentivity), resulting in less energy lost per magnetization cycle.", "correct_answer": "A", "concept_tags": ["transformer", "hysteresis-loss", "soft-iron", "B-H-curve"], "payload": {"question_id": "cuet-phy-ac-adv-24", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Narrow hysteresis loop (e.g. soft iron)", "is_correct": true}, {"key": "B", "value": "Wide hysteresis loop (e.g. steel)", "is_correct": false}, {"key": "C", "value": "High coercivity", "is_correct": false}, {"key": "D", "value": "High retentivity", "is_correct": false}], "elimination_hints": ["Wide hysteresis loop means more area → more energy loss per cycle.", "High coercivity materials (like steel) are used for permanent magnets, not transformer cores.", "Narrow loop = low coercivity + low retentivity = less hysteresis loss."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A transformer with 90% efficiency has a primary voltage of 200 V and delivers power to a 20 Ω load connected to its secondary at 40 V. The primary current drawn is approximately:", "explanation": "Secondary current I_s = V_s/R_load = 40/20 = 2 A. Output power = V_s × I_s = 40 × 2 = 80 W. Efficiency η = P_out/P_in → P_in = P_out/η = 80/0.9 ≈ 88.9 W. Primary current I_p = P_in/V_p = 88.9/200 ≈ 0.44 A.", "correct_answer": "C", "concept_tags": ["transformer", "efficiency", "numerical", "power"], "payload": {"question_id": "cuet-phy-ac-adv-25", "subtopic": "transformer efficiency", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "0.2 A", "is_correct": false}, {"key": "B", "value": "0.4 A", "is_correct": false}, {"key": "C", "value": "0.44 A", "is_correct": true}, {"key": "D", "value": "0.8 A", "is_correct": false}], "elimination_hints": ["0.4 A assumes 100% efficiency (ideal transformer).", "0.8 A comes from incorrect calculation: I_p must be greater than 0.4 A (ideal) due to losses, but not double.", "P_in = 80/0.9 ≈ 88.9 W → I_p = 88.9/200 ≈ 0.44 A."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An ideal step-down transformer converts 2200 V to 220 V. If the secondary coil has 50 turns, the number of turns in the primary coil is:", "explanation": "For an ideal transformer, V_p/V_s = N_p/N_s. So N_p = N_s × (V_p/V_s) = 50 × (2200/220) = 50 × 10 = 500 turns. The step-down ratio is 10:1.", "correct_answer": "B", "concept_tags": ["transformer", "turns-ratio", "step-down", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-26", "subtopic": "transformer calculations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "50", "is_correct": false}, {"key": "B", "value": "500", "is_correct": true}, {"key": "C", "value": "5000", "is_correct": false}, {"key": "D", "value": "5", "is_correct": false}], "elimination_hints": ["50 turns for primary would mean a 1:1 ratio, not a step-down.", "V_p/V_s = 2200/220 = 10, so N_p = 10 × N_s = 10 × 50 = 500.", "5000 would require a 100:1 ratio which doesn''t match 2200:220."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a transformer, flux leakage leads to:", "explanation": "Flux leakage means not all the magnetic flux produced by the primary coil links with the secondary coil. This reduces the EMF induced in the secondary, decreasing the output voltage and power. It reduces the efficiency of the transformer.", "correct_answer": "D", "concept_tags": ["transformer", "flux-leakage", "efficiency"], "payload": {"question_id": "cuet-phy-ac-adv-27", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Increased output voltage", "is_correct": false}, {"key": "B", "value": "Increased efficiency", "is_correct": false}, {"key": "C", "value": "No effect on performance", "is_correct": false}, {"key": "D", "value": "Reduced output voltage and efficiency", "is_correct": true}], "elimination_hints": ["Less flux linking secondary means less induced EMF → lower output voltage.", "Flux leakage is a loss mechanism — it reduces efficiency, not increases it.", "Any energy lost to leakage flux is energy not transferred to the secondary."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A town 10 km away receives electrical power from a power plant. The power plant generates 2 MW at 10 kV. The two-wire transmission line has a resistance of 0.5 Ω/km. The power loss in the line is:", "explanation": "Total wire length = 2 × 10 = 20 km (two wires). Total resistance R = 20 × 0.5 = 10 Ω. Current I = P/V = 2 × 10⁶ / (10 × 10³) = 200 A. Power loss = I²R = 200² × 10 = 40000 × 10 = 400,000 W = 400 kW. Percentage loss = (400/2000) × 100 = 20%.", "correct_answer": "C", "concept_tags": ["power-transmission", "line-loss", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-28", "subtopic": "power transmission", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "100 kW", "is_correct": false}, {"key": "B", "value": "200 kW", "is_correct": false}, {"key": "C", "value": "400 kW", "is_correct": true}, {"key": "D", "value": "800 kW", "is_correct": false}], "elimination_hints": ["Two wires of 10 km each → total resistance = 20 × 0.5 = 10 Ω.", "I = 2 × 10⁶ / 10⁴ = 200 A; Loss = 200² × 10 = 400,000 W.", "200 kW uses only one wire''s resistance (5 Ω) — must count both wires."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LC oscillating circuit, the capacitor has maximum charge q₀ and the inductance is L. The maximum current in the circuit is:", "explanation": "By energy conservation: ½q₀²/C = ½LI₀². Also, I₀ = q₀ω = q₀/√(LC). Alternatively, from ½q₀²/C = ½LI₀², we get I₀ = q₀/√(LC). The maximum current occurs when the capacitor is fully discharged.", "correct_answer": "A", "concept_tags": ["LC-oscillation", "maximum-current", "energy-conservation"], "payload": {"question_id": "cuet-phy-ac-adv-29", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "q₀/√(LC)", "is_correct": true}, {"key": "B", "value": "q₀√(LC)", "is_correct": false}, {"key": "C", "value": "q₀/(LC)", "is_correct": false}, {"key": "D", "value": "q₀√(L/C)", "is_correct": false}], "elimination_hints": ["q₀√(LC) has dimensions of charge × time, not current.", "I₀ = q₀ω = q₀ × 1/√(LC) = q₀/√(LC).", "Dimensional check: [q₀/√(LC)] = C/√(H·F) = C/√(s²) = C/s = A ✓"]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An LC circuit has L = 0.2 H and C = 5 μF. The capacitor is initially charged to 10 mC. The maximum current in the circuit is:", "explanation": "I₀ = q₀/√(LC) = 10 × 10⁻³ / √(0.2 × 5 × 10⁻⁶) = 10⁻² / √(10⁻⁶) = 10⁻² / 10⁻³ = 10 A. Alternatively, ω = 1/√(LC) = 1/10⁻³ = 1000 rad/s, and I₀ = q₀ω = 10⁻² × 10³ = 10 A.", "correct_answer": "D", "concept_tags": ["LC-oscillation", "maximum-current", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-30", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "0.1 A", "is_correct": false}, {"key": "B", "value": "1 A", "is_correct": false}, {"key": "C", "value": "5 A", "is_correct": false}, {"key": "D", "value": "10 A", "is_correct": true}], "elimination_hints": ["LC = 0.2 × 5 × 10⁻⁶ = 10⁻⁶, so √(LC) = 10⁻³.", "I₀ = q₀/√(LC) = 10 × 10⁻³ / 10⁻³ = 10 A.", "Common error: forgetting to convert mC to C gives I₀ = 10000 A (way too high)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the LC-SHM analogy, the quantity analogous to the potential energy (½kx²) of the spring-mass system is:", "explanation": "In the analogy: q ↔ x, I ↔ v, L ↔ m, 1/C ↔ k. Potential energy ½kx² ↔ ½(1/C)q² = q²/(2C), which is the energy stored in the capacitor (electric field energy). Kinetic energy ½mv² ↔ ½LI² (magnetic energy in the inductor).", "correct_answer": "B", "concept_tags": ["LC-oscillation", "SHM-analogy", "energy"], "payload": {"question_id": "cuet-phy-ac-adv-31", "subtopic": "LC oscillations — SHM analogy", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "½LI² (energy in inductor)", "is_correct": false}, {"key": "B", "value": "q²/(2C) (energy in capacitor)", "is_correct": true}, {"key": "C", "value": "½CV² (energy in capacitor)", "is_correct": false}, {"key": "D", "value": "LI (flux linkage)", "is_correct": false}], "elimination_hints": ["½LI² is analogous to ½mv² (kinetic energy), not potential energy.", "½CV² is the same as q²/(2C) but written in terms of V; the direct analogy uses q (↔ x).", "Potential energy involves the ''displacement'' variable: ½kx² ↔ q²/(2C)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is NOT a source of energy loss in a real transformer?", "explanation": "Energy losses in a real transformer include: copper loss (I²R in windings), eddy current loss (induced currents in core), hysteresis loss (repeated magnetization of core), and flux leakage. Dielectric loss occurs in capacitors, not in transformers.", "correct_answer": "D", "concept_tags": ["transformer", "energy-loss", "efficiency"], "payload": {"question_id": "cuet-phy-ac-adv-32", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "Copper loss", "is_correct": false}, {"key": "B", "value": "Eddy current loss", "is_correct": false}, {"key": "C", "value": "Hysteresis loss", "is_correct": false}, {"key": "D", "value": "Dielectric loss", "is_correct": true}], "elimination_hints": ["Copper loss (I²R) definitely occurs in the windings.", "Eddy current and hysteresis losses occur in the iron core.", "Dielectric loss is associated with capacitors and insulators, not transformer operation."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A step-up transformer has a turns ratio of 1:10. If the primary current is 5 A, the secondary current for an ideal transformer is:", "explanation": "For an ideal transformer, I_p/I_s = N_s/N_p (current is inversely proportional to turns ratio). I_s = I_p × (N_p/N_s) = 5 × (1/10) = 0.5 A. A step-up transformer increases voltage but decreases current proportionally.", "correct_answer": "A", "concept_tags": ["transformer", "current-ratio", "step-up", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-33", "subtopic": "transformer calculations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "0.5 A", "is_correct": true}, {"key": "B", "value": "5 A", "is_correct": false}, {"key": "C", "value": "50 A", "is_correct": false}, {"key": "D", "value": "0.05 A", "is_correct": false}], "elimination_hints": ["5 A would mean no change in current (1:1 transformer).", "50 A would mean the current increased — this happens in a step-down, not step-up.", "In a step-up transformer, voltage increases so current must decrease: I_s = 5/10 = 0.5 A."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Assertion (A): A transformer cannot work with direct current (DC).\nReason (R): A transformer works on the principle of mutual induction which requires a changing magnetic flux.", "explanation": "DC produces a constant current and hence a constant magnetic flux in the primary. A constant flux does not induce any EMF in the secondary (Faraday''s law: EMF = −dΦ/dt = 0 for constant Φ). Moreover, with DC, the primary acts as a short circuit (only resistance, no reactance), drawing excessive current that can burn the windings.", "correct_answer": "A", "concept_tags": ["transformer", "DC", "mutual-induction", "assertion-reason"], "payload": {"question_id": "cuet-phy-ac-adv-34", "subtopic": "transformer principle", "topic_name": "AC Circuits — Advanced", "bloom_level": "evaluate", "options": [{"key": "A", "value": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "value": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "value": "A is true but R is false", "is_correct": false}, {"key": "D", "value": "A is false but R is true", "is_correct": false}], "elimination_hints": ["The transformer indeed cannot work with DC — assertion A is true.", "Mutual induction requires dΦ/dt ≠ 0, which needs AC — reason R is true.", "R directly explains A: the changing flux requirement is why DC fails."]}}]'::jsonb, 'deploy-2026-03-05-b07');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LCR circuit connected to an AC source, the current is in phase with the voltage. This means:", "explanation": "Current in phase with voltage means φ = 0°, which occurs when X_L = X_C (reactances cancel). This is the condition for resonance in a series LCR circuit. At resonance, Z = R (minimum impedance) and current is maximum.", "correct_answer": "C", "concept_tags": ["resonance", "phase", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-adv-35", "subtopic": "resonance conditions", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "X_L > X_C", "is_correct": false}, {"key": "B", "value": "X_L < X_C", "is_correct": false}, {"key": "C", "value": "X_L = X_C (resonance)", "is_correct": true}, {"key": "D", "value": "R = 0", "is_correct": false}], "elimination_hints": ["X_L > X_C makes the circuit inductive — current lags voltage.", "X_L < X_C makes the circuit capacitive — current leads voltage.", "In-phase condition requires net reactance = 0, i.e., X_L = X_C."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In an LCR series circuit, R = 10 Ω, L = 0.5 H, and C = 50 μF. The circuit is connected to a 220 V, 50 Hz AC source. The current in the circuit is approximately:", "explanation": "ω = 2πf = 2π × 50 = 100π rad/s. X_L = ωL = 100π × 0.5 = 50π ≈ 157 Ω. X_C = 1/(ωC) = 1/(100π × 50 × 10⁻⁶) = 1/(5π × 10⁻³) = 200/π ≈ 63.7 Ω. Z = √(R² + (X_L − X_C)²) = √(100 + (157 − 63.7)²) = √(100 + 8700) = √8800 ≈ 93.8 Ω. I = V/Z = 220/93.8 ≈ 2.34 A.", "correct_answer": "B", "concept_tags": ["LCR-circuit", "impedance", "numerical", "current"], "payload": {"question_id": "cuet-phy-ac-adv-36", "subtopic": "LCR circuit numerical", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "1.0 A", "is_correct": false}, {"key": "B", "value": "2.3 A", "is_correct": true}, {"key": "C", "value": "5.0 A", "is_correct": false}, {"key": "D", "value": "22.0 A", "is_correct": false}], "elimination_hints": ["22.0 A would require Z = 10 Ω (only R), ignoring reactances.", "X_L − X_C ≈ 93 Ω, so Z ≈ √(100 + 8700) ≈ 94 Ω.", "I = 220/94 ≈ 2.3 A."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In the above circuit (R = 10 Ω, L = 0.5 H, C = 50 μF, f = 50 Hz), the resonant frequency is approximately:", "explanation": "f₀ = 1/(2π√(LC)) = 1/(2π√(0.5 × 50 × 10⁻⁶)) = 1/(2π√(25 × 10⁻⁶)) = 1/(2π × 5 × 10⁻³) = 1/(10π × 10⁻³) = 1000/(10π) = 100/π ≈ 31.8 Hz. The circuit is being driven at 50 Hz, which is above resonance.", "correct_answer": "A", "concept_tags": ["resonant-frequency", "LCR-circuit", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-37", "subtopic": "LCR circuit numerical", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "100/π Hz ≈ 31.8 Hz", "is_correct": true}, {"key": "B", "value": "50 Hz", "is_correct": false}, {"key": "C", "value": "100 Hz", "is_correct": false}, {"key": "D", "value": "200/π Hz ≈ 63.7 Hz", "is_correct": false}], "elimination_hints": ["50 Hz is the driving frequency, not the resonant frequency.", "LC = 0.5 × 50 × 10⁻⁶ = 25 × 10⁻⁶, √(LC) = 5 × 10⁻³.", "f₀ = 1/(2π × 5 × 10⁻³) = 100/π ≈ 31.8 Hz."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The power factor of a series RL circuit with R = 30 Ω and X_L = 40 Ω is:", "explanation": "Power factor cos φ = R/Z. Impedance Z = √(R² + X_L²) = √(900 + 1600) = √2500 = 50 Ω. cos φ = R/Z = 30/50 = 0.6. The phase angle φ = cos⁻¹(0.6) ≈ 53.13°.", "correct_answer": "C", "concept_tags": ["power-factor", "RL-circuit", "impedance", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-38", "subtopic": "power factor", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "0.4", "is_correct": false}, {"key": "B", "value": "0.5", "is_correct": false}, {"key": "C", "value": "0.6", "is_correct": true}, {"key": "D", "value": "0.8", "is_correct": false}], "elimination_hints": ["0.8 = 40/50 = X_L/Z, which is sin φ, not cos φ.", "0.4 = R/X_L — this is not the power factor formula.", "Power factor = R/Z = 30/50 = 0.6. It''s a 3-4-5 right triangle scaled by 10."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Match the following AC circuit parameters (Column-I) with their expressions (Column-II):\nColumn-I: (P) Impedance of LCR circuit (Q) Resonant frequency (R) Power factor (S) Q-factor\nColumn-II: (1) R/Z (2) √(R² + (X_L − X_C)²) (3) ω₀L/R (4) 1/(2π√(LC))", "explanation": "(P) Impedance Z = √(R² + (X_L − X_C)²) → (2). (Q) Resonant frequency f₀ = 1/(2π√(LC)) → (4). (R) Power factor cos φ = R/Z → (1). (S) Q-factor = ω₀L/R → (3).", "correct_answer": "B", "concept_tags": ["LCR-circuit", "matching", "formulas"], "payload": {"question_id": "cuet-phy-ac-adv-39", "subtopic": "AC circuit formulas", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "P→1, Q→2, R→3, S→4", "is_correct": false}, {"key": "B", "value": "P→2, Q→4, R→1, S→3", "is_correct": true}, {"key": "C", "value": "P→2, Q→3, R→4, S→1", "is_correct": false}, {"key": "D", "value": "P→4, Q→2, R→3, S→1", "is_correct": false}], "elimination_hints": ["Impedance involves square root of R² plus reactance difference squared → (2).", "Resonant frequency has 1/(2π√(LC)) → (4).", "Power factor = cos φ = R/Z → (1); Q = ω₀L/R → (3)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Assertion (A): At resonance in a series LCR circuit, the voltage across the inductor can be much greater than the applied voltage.\nReason (R): The Q-factor of the circuit amplifies the voltage across individual reactive components at resonance.", "explanation": "At resonance, V_L = IX_L = (V/R)(ω₀L) = V(ω₀L/R) = VQ. Since Q can be much greater than 1 (e.g., Q = 50), the voltage across L (or C) can be 50 times the applied voltage. This voltage amplification is the essence of the Q-factor. Both A and R are true, and R correctly explains A.", "correct_answer": "A", "concept_tags": ["resonance", "Q-factor", "voltage-amplification", "assertion-reason"], "payload": {"question_id": "cuet-phy-ac-adv-40", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "evaluate", "options": [{"key": "A", "value": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "value": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "value": "A is true but R is false", "is_correct": false}, {"key": "D", "value": "A is false but R is true", "is_correct": false}], "elimination_hints": ["V_L = VQ at resonance, and Q can be >> 1, so V_L >> V. Assertion A is true.", "The Q-factor is precisely the ratio V_L/V (or V_C/V) at resonance. Reason R is true.", "R directly explains A — the voltage amplification is due to the Q-factor."]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is NOT an electromagnetic wave?", "explanation": "Ultrasound waves are mechanical (longitudinal) waves that require a material medium for propagation. They are pressure variations in air, water, or tissue. All the other options — X-rays, microwaves, and gamma rays — are electromagnetic waves that can travel through vacuum.", "correct_answer": "C", "concept_tags": ["em-wave-types", "mechanical-vs-em", "ultrasound"], "payload": {"question_id": "cuet-phy-emwave-21", "subtopic": "nature of electromagnetic waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "X-rays", "is_correct": false}, {"key": "B", "text": "Microwaves", "is_correct": false}, {"key": "C", "text": "Ultrasound waves", "is_correct": true}, {"key": "D", "text": "Gamma rays", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "X-rays are high-frequency electromagnetic waves used in medical imaging. They travel through vacuum.", "misconception": "Thinking X-rays need a medium"}, {"option_key": "B", "hint": "Microwaves are EM waves with wavelengths in the cm range, used in ovens and communication.", "misconception": "Confusing microwaves with sound waves"}, {"option_key": "D", "hint": "Gamma rays are the highest-frequency electromagnetic waves, emitted by radioactive nuclei.", "misconception": "Confusing nuclear radiation with mechanical waves"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Electromagnetic waves travel in vacuum with a speed of:", "explanation": "All electromagnetic waves travel in vacuum at the speed of light, c = 3 × 10⁸ m/s, regardless of their frequency or wavelength. This is a fundamental constant of nature derived from Maxwell''s equations: c = 1/√(μ₀ε₀).", "correct_answer": "B", "concept_tags": ["speed-of-light", "vacuum", "maxwell-equations"], "payload": {"question_id": "cuet-phy-emwave-22", "subtopic": "speed of electromagnetic waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "3 × 10⁶ m/s", "is_correct": false}, {"key": "B", "text": "3 × 10⁸ m/s", "is_correct": false}, {"key": "C", "text": "3 × 10¹⁰ m/s", "is_correct": false}, {"key": "D", "text": "Speed depends on wavelength", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3 × 10⁶ m/s is 1000 times slower than light. This is roughly 1% of the speed of light.", "misconception": "Confusing order of magnitude"}, {"option_key": "C", "hint": "3 × 10¹⁰ m/s would exceed the speed of light, violating special relativity.", "misconception": "Exaggerating the speed of EM waves"}, {"option_key": "D", "hint": "In vacuum, all EM waves travel at the same speed c, regardless of wavelength. Speed depends on wavelength only in a dispersive medium.", "misconception": "Applying medium-dispersion properties to vacuum"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which electromagnetic waves are used in RADAR systems?", "explanation": "RADAR (Radio Detection And Ranging) uses microwaves, typically in the frequency range of 1–300 GHz. Microwaves are ideal because they can penetrate clouds, are reflected well by metallic objects, and can be focused into narrow beams using dish antennas.", "correct_answer": "C", "concept_tags": ["radar", "microwaves", "applications"], "payload": {"question_id": "cuet-phy-emwave-23", "subtopic": "applications of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Infrared waves", "is_correct": false}, {"key": "B", "text": "Ultraviolet rays", "is_correct": false}, {"key": "C", "text": "Microwaves", "is_correct": true}, {"key": "D", "text": "Gamma rays", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Infrared waves are used in remote controls, night vision, and thermal imaging — not in RADAR.", "misconception": "Confusing IR applications with RADAR"}, {"option_key": "B", "hint": "UV rays are absorbed by the atmosphere and are used in sterilisation, not for detection and ranging.", "misconception": "Mixing up UV applications"}, {"option_key": "D", "hint": "Gamma rays are extremely high-energy and penetrating — impractical and dangerous for detection systems.", "misconception": "Thinking higher energy means better detection"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The wavelength range of visible light is approximately:", "explanation": "Visible light spans roughly 400 nm (violet) to 700 nm (red). This narrow band of the electromagnetic spectrum is the only portion detectable by the human eye. Below 400 nm lies ultraviolet, and above 700 nm lies infrared.", "correct_answer": "B", "concept_tags": ["visible-light", "wavelength-range", "spectrum"], "payload": {"question_id": "cuet-phy-emwave-24", "subtopic": "electromagnetic spectrum", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "1 nm to 400 nm", "is_correct": false}, {"key": "B", "text": "400 nm to 700 nm", "is_correct": true}, {"key": "C", "text": "700 nm to 1 mm", "is_correct": false}, {"key": "D", "text": "1 mm to 1 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1–400 nm covers ultraviolet and X-ray ranges, which are invisible to the human eye.", "misconception": "Confusing UV range with visible light"}, {"option_key": "C", "hint": "700 nm to 1 mm is the infrared region, felt as heat but not seen by the eye.", "misconception": "Extending visible range into infrared"}, {"option_key": "D", "hint": "1 mm to 1 m is the microwave range, used in communication and cooking.", "misconception": "Confusing microwave with visible wavelengths"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the electric field component of an EM wave is E₀ sin(kz − ωt)x̂, the magnetic field component is:", "explanation": "In an electromagnetic wave, E and B are perpendicular to each other and to the direction of propagation. If E is along x̂ and propagation is along ẑ, then B must be along ŷ. The amplitude relation is B₀ = E₀/c. Both fields have the same phase, so B = (E₀/c) sin(kz − ωt)ŷ.", "correct_answer": "A", "concept_tags": ["E-B-relation", "wave-propagation", "amplitude-ratio"], "payload": {"question_id": "cuet-phy-emwave-25", "subtopic": "relation between E and B", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "(E₀/c) sin(kz − ωt)ŷ", "is_correct": true}, {"key": "B", "text": "E₀c sin(kz − ωt)ŷ", "is_correct": false}, {"key": "C", "text": "(E₀/c) sin(kz − ωt)ẑ", "is_correct": false}, {"key": "D", "text": "(E₀/c) cos(kz − ωt)ŷ", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "B₀ = E₀/c, not E₀c. Since c ≈ 3×10⁸, E₀c would give an enormously large magnetic field.", "misconception": "Inverting the E-B amplitude relation"}, {"option_key": "C", "hint": "ẑ is the direction of propagation. B cannot oscillate along the direction of wave travel — EM waves are transverse.", "misconception": "Placing B along the propagation direction"}, {"option_key": "D", "hint": "E and B are in phase in an EM wave. If E has sin(kz − ωt), B also has sin(kz − ωt), not cos.", "misconception": "Thinking E and B have a 90° phase difference"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ozone layer in the Earth''s atmosphere absorbs mainly:", "explanation": "The ozone (O₃) layer in the stratosphere strongly absorbs ultraviolet (UV) radiation from the Sun, particularly UV-B (280–315 nm) and UV-C (100–280 nm). This absorption protects living organisms from harmful UV radiation that can cause skin cancer and DNA damage.", "correct_answer": "B", "concept_tags": ["ozone-layer", "uv-absorption", "atmosphere"], "payload": {"question_id": "cuet-phy-emwave-26", "subtopic": "applications and effects of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Infrared radiation", "is_correct": false}, {"key": "B", "text": "Ultraviolet radiation", "is_correct": true}, {"key": "C", "text": "Visible light", "is_correct": false}, {"key": "D", "text": "Radio waves", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Infrared is mainly absorbed by water vapour and CO₂ (greenhouse gases), not ozone.", "misconception": "Confusing ozone absorption with greenhouse effect"}, {"option_key": "C", "hint": "Visible light passes through the atmosphere largely unabsorbed — that''s why we can see the Sun.", "misconception": "Thinking ozone blocks visible light"}, {"option_key": "D", "hint": "Radio waves pass through the atmosphere and are not absorbed by ozone. The ionosphere reflects some radio waves.", "misconception": "Confusing ozone layer with ionosphere"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The displacement current through a parallel plate capacitor of capacitance C is related to the voltage V across it by:", "explanation": "Displacement current Id = ε₀(dΦE/dt). For a parallel plate capacitor, ΦE = Q/(ε₀) and Q = CV, so Id = dQ/dt = C(dV/dt). This equals the conduction current flowing in the external circuit, maintaining continuity of current through the capacitor gap.", "correct_answer": "C", "concept_tags": ["displacement-current", "capacitor", "maxwell"], "payload": {"question_id": "cuet-phy-emwave-27", "subtopic": "displacement current", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "Id = V/C", "is_correct": false}, {"key": "B", "text": "Id = CV", "is_correct": false}, {"key": "C", "text": "Id = C(dV/dt)", "is_correct": true}, {"key": "D", "text": "Id = V(dC/dt)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "V/C has units of V/F = Coulombs, not Amperes. Current must involve a time derivative.", "misconception": "Confusing charge with current"}, {"option_key": "B", "hint": "CV gives charge Q, not current. You need the rate of change of charge for current.", "misconception": "Forgetting that current is dQ/dt, not Q"}, {"option_key": "D", "hint": "Capacitance C is fixed for a given capacitor geometry; dC/dt = 0 under normal conditions.", "misconception": "Thinking capacitance varies with time"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following EM waves has the longest wavelength?", "explanation": "In the electromagnetic spectrum, radio waves have the longest wavelength (ranging from ~1 mm to thousands of kilometres). The order from longest to shortest wavelength is: radio > microwave > infrared > visible > UV > X-ray > gamma ray.", "correct_answer": "D", "concept_tags": ["spectrum-order", "wavelength-comparison", "radio-waves"], "payload": {"question_id": "cuet-phy-emwave-28", "subtopic": "electromagnetic spectrum ordering", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "X-rays", "is_correct": false}, {"key": "B", "text": "Infrared rays", "is_correct": false}, {"key": "C", "text": "Microwaves", "is_correct": false}, {"key": "D", "text": "Radio waves", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "X-rays have very short wavelengths (0.01–10 nm), among the shortest in the EM spectrum.", "misconception": "Confusing penetrating power with wavelength"}, {"option_key": "B", "hint": "Infrared has wavelengths from ~700 nm to 1 mm — longer than visible but shorter than microwaves and radio.", "misconception": "Thinking IR is the longest wavelength"}, {"option_key": "C", "hint": "Microwaves (1 mm to ~30 cm) are longer than IR but shorter than radio waves.", "misconception": "Confusing microwave and radio wave ranges"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An EM wave has a frequency of 5 × 10¹⁴ Hz. Its wavelength is:", "explanation": "Using c = fλ, we get λ = c/f = (3 × 10⁸)/(5 × 10¹⁴) = 6 × 10⁻⁷ m = 600 nm. This falls in the visible light range (orange-yellow region), confirming the answer is reasonable.", "correct_answer": "B", "concept_tags": ["wavelength-frequency", "c-equals-f-lambda", "numerical"], "payload": {"question_id": "cuet-phy-emwave-29", "subtopic": "wave equation c = fλ", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "6 × 10⁻⁵ m", "is_correct": false}, {"key": "B", "text": "6 × 10⁻⁷ m", "is_correct": true}, {"key": "C", "text": "6 × 10⁻⁹ m", "is_correct": false}, {"key": "D", "text": "6 × 10⁻³ m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6 × 10⁻⁵ m = 60 μm, which lies in the far infrared — too long for a frequency of 10¹⁴ Hz.", "misconception": "Error in power of ten calculation"}, {"option_key": "C", "hint": "6 × 10⁻⁹ m = 6 nm, which is in the X-ray range — way too short for visible frequency.", "misconception": "Subtracting exponents incorrectly: 8−14 ≠ −9"}, {"option_key": "D", "hint": "6 × 10⁻³ m = 6 mm lies in the microwave range. This would correspond to a much lower frequency (~50 GHz).", "misconception": "Major arithmetic error in exponents"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The intensity of an electromagnetic wave is proportional to:", "explanation": "The intensity (power per unit area) of an EM wave is I = ½ε₀cE₀², so it is proportional to the square of the amplitude of the electric field. Equivalently, I = B₀²c/(2μ₀). Intensity is proportional to E₀², not E₀ or E₀³.", "correct_answer": "B", "concept_tags": ["intensity", "electric-field-amplitude", "energy"], "payload": {"question_id": "cuet-phy-emwave-30", "subtopic": "intensity of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "E₀", "is_correct": false}, {"key": "B", "text": "E₀²", "is_correct": true}, {"key": "C", "text": "E₀³", "is_correct": false}, {"key": "D", "text": "1/E₀²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Intensity involves energy, which depends on the square of the field amplitude — just like kinetic energy depends on v².", "misconception": "Forgetting the squared dependence of energy on amplitude"}, {"option_key": "C", "hint": "No standard wave formula involves the cube of amplitude. Energy density is always proportional to amplitude².", "misconception": "Randomly guessing the power dependence"}, {"option_key": "D", "hint": "Intensity increases with stronger electric field. An inverse-square relation would mean weaker fields give more energy.", "misconception": "Inverting the relationship"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A plane electromagnetic wave of frequency 25 MHz travels in free space along the x-direction. At a particular point and time, E = 6.3 V/m ŷ. The magnetic field B at that point and time is:", "explanation": "B₀ = E₀/c = 6.3/(3 × 10⁸) = 2.1 × 10⁻⁸ T. Since E is along ŷ and wave propagates along x̂, B must be along ẑ (using E × B ∝ direction of propagation: ŷ × ẑ = x̂). So B = 2.1 × 10⁻⁸ T ẑ.", "correct_answer": "A", "concept_tags": ["E-B-numerical", "direction", "cross-product"], "payload": {"question_id": "cuet-phy-emwave-31", "subtopic": "E and B field calculation", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "2.1 × 10⁻⁸ T ẑ", "is_correct": true}, {"key": "B", "text": "2.1 × 10⁻⁸ T x̂", "is_correct": false}, {"key": "C", "text": "1.89 × 10⁹ T ẑ", "is_correct": false}, {"key": "D", "text": "2.1 × 10⁻⁸ T (−ẑ)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "x̂ is the direction of propagation. B cannot point along the wave''s travel direction — EM waves are transverse.", "misconception": "Placing B along propagation direction"}, {"option_key": "C", "hint": "This value uses B = Ec instead of B = E/c. The magnetic field amplitude is always much smaller than E in SI units.", "misconception": "Using B = Ec instead of B = E/c"}, {"option_key": "D", "hint": "For E along +ŷ and propagation along +x̂, E × B must give +x̂. ŷ × ẑ = x̂ (correct), but ŷ × (−ẑ) = −x̂ (wrong direction).", "misconception": "Getting the cross-product sign wrong"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An EM wave of wavelength λ is incident on a slit of width d. Diffraction effects are significant when:", "explanation": "Diffraction becomes significant when the wavelength is comparable to or larger than the obstacle/slit size, i.e., λ ≥ d (or d ≈ λ). When d >> λ, the wave passes through with negligible diffraction (ray optics limit). When d << λ, the wave bends around the slit almost completely.", "correct_answer": "C", "concept_tags": ["diffraction-condition", "wavelength-slit", "wave-nature"], "payload": {"question_id": "cuet-phy-emwave-32", "subtopic": "wave properties of EM radiation", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "d >> λ", "is_correct": false}, {"key": "B", "text": "d << λ", "is_correct": false}, {"key": "C", "text": "d ≈ λ", "is_correct": true}, {"key": "D", "text": "λ = 0", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "When d >> λ, the slit is much wider than the wavelength — light goes straight through with minimal bending (geometric optics).", "misconception": "Thinking large slit causes more diffraction"}, {"option_key": "B", "hint": "When d << λ, diffraction is extreme (wave bends around completely), but the question asks when effects become ''significant'' — the onset is at d ≈ λ.", "misconception": "Partially correct but not the threshold condition"}, {"option_key": "D", "hint": "λ = 0 would mean infinite frequency — no real wave has zero wavelength.", "misconception": "Not understanding the physical meaning"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The average energy density in an electromagnetic wave with electric field amplitude E₀ is:", "explanation": "The average energy density of an EM wave is u = ½ε₀E₀². This can also be written as u = B₀²/(2μ₀). The electric and magnetic field contributions are equal: uE = ¼ε₀E₀² and uB = ¼ε₀E₀², giving total u = ½ε₀E₀².", "correct_answer": "B", "concept_tags": ["energy-density", "electric-field", "average"], "payload": {"question_id": "cuet-phy-emwave-33", "subtopic": "energy in EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "ε₀E₀²", "is_correct": false}, {"key": "B", "text": "½ε₀E₀²", "is_correct": true}, {"key": "C", "text": "¼ε₀E₀²", "is_correct": false}, {"key": "D", "text": "2ε₀E₀²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "ε₀E₀² is the peak energy density of the electric field alone. The average (over one cycle) introduces a factor of ½.", "misconception": "Forgetting to take the time average of sin²"}, {"option_key": "C", "hint": "¼ε₀E₀² is the average energy density of only the electric field part. You must add the equal magnetic field contribution.", "misconception": "Forgetting the magnetic field contribution"}, {"option_key": "D", "hint": "2ε₀E₀² is four times the correct answer. There''s no physical basis for this factor.", "misconception": "Doubling both peak and average incorrectly"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electromagnetic wave with the highest penetrating power is:", "explanation": "Gamma rays have the shortest wavelength and highest frequency among EM waves, giving them the highest energy per photon (E = hf). This high energy allows them to penetrate through most materials, including metals and body tissues. X-rays also penetrate well but less than gamma rays.", "correct_answer": "D", "concept_tags": ["penetrating-power", "gamma-rays", "energy-frequency"], "payload": {"question_id": "cuet-phy-emwave-34", "subtopic": "properties of EM spectrum regions", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Visible light", "is_correct": false}, {"key": "B", "text": "Infrared", "is_correct": false}, {"key": "C", "text": "X-rays", "is_correct": false}, {"key": "D", "text": "Gamma rays", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Visible light is blocked by opaque materials and has much lower photon energy than X-rays or gamma rays.", "misconception": "Thinking visible light penetrates well because we see through glass"}, {"option_key": "B", "hint": "Infrared is absorbed by most solids and has very low penetrating power compared to high-frequency radiation.", "misconception": "Confusing heat penetration with radiation penetration"}, {"option_key": "C", "hint": "X-rays have high penetrating power and are used in medical imaging, but gamma rays have even higher energy and penetrate more.", "misconception": "Thinking X-rays are the most penetrating — close but gamma rays exceed them"}]}}]'::jsonb, 'deploy-2026-03-05-b07');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Maxwell''s equations predict that the speed of electromagnetic waves in a medium of permittivity ε and permeability μ is:", "explanation": "From Maxwell''s equations, the wave speed in a medium is v = 1/√(με). In vacuum, this gives c = 1/√(μ₀ε₀) = 3 × 10⁸ m/s. In any medium, ε > ε₀ and μ > μ₀ (usually), so v < c — electromagnetic waves slow down in a medium.", "correct_answer": "A", "concept_tags": ["maxwell-speed", "permittivity", "permeability"], "payload": {"question_id": "cuet-phy-emwave-35", "subtopic": "Maxwell''s equations and wave speed", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "1/√(με)", "is_correct": true}, {"key": "B", "text": "√(με)", "is_correct": false}, {"key": "C", "text": "1/(με)", "is_correct": false}, {"key": "D", "text": "με", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "√(με) would give speed in units of √(H·F/m²). Dimensionally, speed should be m/s = 1/√(με).", "misconception": "Inverting the formula"}, {"option_key": "C", "hint": "1/(με) has wrong dimensions. Check: [1/(με)] = m²/(H·F) which is not m/s.", "misconception": "Forgetting the square root"}, {"option_key": "D", "hint": "με has dimensions of H·F/m² = s²/m². This is the reciprocal of speed squared, not speed.", "misconception": "Completely inverting the relationship"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The radiation pressure exerted by an electromagnetic wave of intensity I on a perfectly reflecting surface is:", "explanation": "When an EM wave of intensity I strikes a perfectly reflecting surface, the radiation pressure is p = 2I/c. For a perfectly absorbing surface, it would be I/c. The factor of 2 for reflection arises because the momentum change is doubled (like a ball bouncing off a wall vs. sticking to it).", "correct_answer": "C", "concept_tags": ["radiation-pressure", "reflection", "momentum"], "payload": {"question_id": "cuet-phy-emwave-36", "subtopic": "momentum and radiation pressure", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "I/c", "is_correct": false}, {"key": "B", "text": "I/c²", "is_correct": false}, {"key": "C", "text": "2I/c", "is_correct": true}, {"key": "D", "text": "Ic", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "I/c is the radiation pressure for a perfectly absorbing (black) surface. Reflection doubles the momentum transfer.", "misconception": "Using the absorption formula for reflection"}, {"option_key": "B", "hint": "I/c² has units of kg/m³, not Pa (N/m²). Dimensionally incorrect for pressure.", "misconception": "Confusing with E = mc² related expressions"}, {"option_key": "D", "hint": "Ic would have units of W²·s/m³ which is not pressure. Also, pressure should decrease with increasing c.", "misconception": "Inverting the c dependence"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following is used in the treatment of cancer?", "explanation": "Gamma rays are used in radiation therapy (radiotherapy) for cancer treatment. Their high energy and penetrating power allow them to destroy cancer cells deep within the body. Cobalt-60 is a common gamma ray source used in cancer treatment. Infrared is used for physiotherapy, UV for sterilisation, and microwaves for communication.", "correct_answer": "A", "concept_tags": ["gamma-rays", "cancer-treatment", "medical-applications"], "payload": {"question_id": "cuet-phy-emwave-37", "subtopic": "medical applications of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Gamma rays", "is_correct": true}, {"key": "B", "text": "Infrared rays", "is_correct": false}, {"key": "C", "text": "Radio waves", "is_correct": false}, {"key": "D", "text": "Microwaves", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Infrared radiation is used for heating and physiotherapy, not for destroying cancer cells.", "misconception": "Confusing thermal therapy with radiation therapy"}, {"option_key": "C", "hint": "Radio waves have very low energy and cannot damage or destroy cells. They are used in communication.", "misconception": "Thinking all radiation can treat cancer"}, {"option_key": "D", "hint": "Microwaves are used in cooking and communication. While microwave ablation exists in surgery, standard cancer radiotherapy uses gamma rays.", "misconception": "Confusing microwave heating with radiation therapy"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The source of infrared radiation is:", "explanation": "All hot bodies emit infrared radiation. Infrared is thermal radiation — any object above absolute zero emits IR, but hot bodies like heaters, the Sun, and human bodies emit significant amounts. IR is detected as heat by our skin.", "correct_answer": "B", "concept_tags": ["infrared", "thermal-radiation", "hot-bodies"], "payload": {"question_id": "cuet-phy-emwave-38", "subtopic": "sources of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Nuclear reactions", "is_correct": false}, {"key": "B", "text": "Hot bodies", "is_correct": true}, {"key": "C", "text": "X-ray tubes", "is_correct": false}, {"key": "D", "text": "Electronic oscillators", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Nuclear reactions primarily produce gamma rays, not infrared. The energy scale is completely different.", "misconception": "Confusing nuclear radiation with thermal radiation"}, {"option_key": "C", "hint": "X-ray tubes produce X-rays by bombarding a metal target with high-speed electrons, not infrared.", "misconception": "Confusing X-ray production with IR emission"}, {"option_key": "D", "hint": "Electronic oscillators produce radio waves and microwaves, not infrared.", "misconception": "Confusing electronic oscillation frequencies with thermal emission"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The momentum carried by an electromagnetic wave of energy U is:", "explanation": "Electromagnetic waves carry momentum p = U/c, where U is the energy and c is the speed of light. This follows from the relativistic energy-momentum relation for massless particles (photons): E = pc. This momentum is responsible for radiation pressure.", "correct_answer": "A", "concept_tags": ["momentum", "energy-momentum", "photon"], "payload": {"question_id": "cuet-phy-emwave-39", "subtopic": "energy and momentum of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "U/c", "is_correct": true}, {"key": "B", "text": "Uc", "is_correct": false}, {"key": "C", "text": "U/c²", "is_correct": false}, {"key": "D", "text": "Uc²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Uc has units of J·m/s = kg·m³/s³. Momentum should have units of kg·m/s.", "misconception": "Inverting the c relationship"}, {"option_key": "C", "hint": "U/c² has units of kg, which is mass — not momentum. This comes from E = mc², a different relation.", "misconception": "Confusing p = U/c with m = E/c²"}, {"option_key": "D", "hint": "Uc² has units of J·m²/s² — dimensionally incorrect for momentum.", "misconception": "Random combination of E and c"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A laser beam of power 10 W is focused on an area of 10⁻⁴ m². The amplitude of the electric field of the EM wave is approximately:", "explanation": "Intensity I = Power/Area = 10/10⁻⁴ = 10⁵ W/m². Using I = ½ε₀cE₀², we get E₀² = 2I/(ε₀c) = 2 × 10⁵/(8.85 × 10⁻¹² × 3 × 10⁸) = 2 × 10⁵/2.655 × 10⁻³ ≈ 7.53 × 10⁷. So E₀ ≈ √(7.53 × 10⁷) ≈ 8.68 × 10³ ≈ 8.7 kV/m.", "correct_answer": "C", "concept_tags": ["intensity-calculation", "electric-field-amplitude", "laser"], "payload": {"question_id": "cuet-phy-emwave-40", "subtopic": "numerical problems on intensity", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "8.7 V/m", "is_correct": false}, {"key": "B", "text": "87 V/m", "is_correct": false}, {"key": "C", "text": "8.7 kV/m", "is_correct": true}, {"key": "D", "text": "87 kV/m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "8.7 V/m is 1000× too small. Check: I for E₀ = 8.7 V/m gives I ≈ 0.1 W/m², not 10⁵ W/m².", "misconception": "Order of magnitude error in calculation"}, {"option_key": "B", "hint": "87 V/m gives I ≈ 10 W/m². Still 10⁴ times less than the required 10⁵ W/m².", "misconception": "Arithmetic error — off by factor of 100"}, {"option_key": "D", "hint": "87 kV/m gives I ≈ 10⁷ W/m², which is 100× more than the given intensity.", "misconception": "Overshooting by a factor of 10 in E₀"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Electromagnetic waves are transverse in nature.\nReason (R): The electric and magnetic field vectors are perpendicular to each other and to the direction of propagation.", "explanation": "Both A and R are true, and R correctly explains A. EM waves are transverse because E and B oscillate perpendicular to the propagation direction. This is fundamentally different from longitudinal waves (like sound) where oscillation is along the propagation direction.", "correct_answer": "A", "concept_tags": ["transverse-nature", "E-B-perpendicular", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-emwave-41", "subtopic": "nature of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The perpendicularity of E, B, and the propagation direction is precisely what makes the wave transverse. R directly explains A.", "misconception": "Thinking the explanation is unrelated"}, {"option_key": "C", "hint": "R is factually correct — E ⊥ B ⊥ direction of propagation is a well-established property of EM waves.", "misconception": "Doubting the perpendicularity of E and B"}, {"option_key": "D", "hint": "A is true — EM waves are indeed transverse. This is confirmed by polarisation experiments.", "misconception": "Thinking EM waves are longitudinal"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The energy of an electromagnetic wave is shared equally between the electric and magnetic fields.\nReason (R): The electric energy density uE = ½ε₀E² equals the magnetic energy density uB = B²/(2μ₀) at every instant in an EM wave.", "explanation": "Both A and R are true, and R correctly explains A. In an EM wave, since B = E/c and c = 1/√(μ₀ε₀), we can show that ½ε₀E² = B²/(2μ₀) at every instant. The energy oscillates between zero and maximum, but at each instant the electric and magnetic contributions are exactly equal.", "correct_answer": "A", "concept_tags": ["energy-equipartition", "energy-density", "E-B-equality"], "payload": {"question_id": "cuet-phy-emwave-42", "subtopic": "energy distribution in EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "analyse", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly proves A — if uE = uB at every instant, then the energy is equally shared. R is the explanation.", "misconception": "Not seeing the direct logical connection"}, {"option_key": "C", "hint": "R is true: substituting B = E/c into B²/(2μ₀) gives E²/(2c²μ₀) = ½ε₀E² since c² = 1/(μ₀ε₀).", "misconception": "Not verifying the mathematical equality"}, {"option_key": "D", "hint": "A is true — equal energy sharing is a fundamental property derived from Maxwell''s equations.", "misconception": "Thinking one field dominates the other"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Radio waves can diffract around buildings and hills.\nReason (R): Radio waves have wavelengths comparable to the size of buildings and hills.", "explanation": "Both A and R are true, and R correctly explains A. Radio waves have wavelengths from metres to kilometres, which are comparable to the size of buildings and hills. Diffraction is significant when the obstacle size is comparable to the wavelength, so radio waves bend around these structures. This is why AM radio signals can be received even behind mountains.", "correct_answer": "A", "concept_tags": ["radio-diffraction", "wavelength-obstacle", "diffraction"], "payload": {"question_id": "cuet-phy-emwave-43", "subtopic": "diffraction of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The comparable wavelength is precisely why diffraction occurs. R is the direct cause of A.", "misconception": "Not connecting diffraction condition to wavelength"}, {"option_key": "C", "hint": "R is correct: AM radio wavelengths are ~100–1000 m, comparable to building and hill sizes.", "misconception": "Underestimating radio wavelengths"}, {"option_key": "D", "hint": "A is true — radio reception behind obstacles is daily evidence of radio wave diffraction.", "misconception": "Thinking radio needs line-of-sight"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Displacement current does not produce a magnetic field.\nReason (R): Displacement current is not a flow of charges.", "explanation": "A is false but R is true. Displacement current IS NOT a flow of charges (R is true — it arises from changing electric field). However, displacement current DOES produce a magnetic field, exactly like conduction current (A is false). This was Maxwell''s key insight: a changing electric field between capacitor plates produces a magnetic field, maintaining the continuity of the Ampere''s circuital law.", "correct_answer": "D", "concept_tags": ["displacement-current", "maxwell-insight", "magnetic-field"], "payload": {"question_id": "cuet-phy-emwave-44", "subtopic": "displacement current and Maxwell''s correction", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "analyse", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A is false — displacement current does produce a magnetic field. That''s the whole point of Maxwell''s modification to Ampere''s law.", "misconception": "Thinking displacement current has no magnetic effect"}, {"option_key": "B", "hint": "A is false, so this option cannot be correct.", "misconception": "Same as above"}, {"option_key": "C", "hint": "R is true — displacement current is ε₀(dΦE/dt), not a flow of actual charges. It exists even in vacuum.", "misconception": "Confusing displacement current with conduction current"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following electromagnetic waves (Column-I) with their sources (Column-II):\n\nColumn-I: (P) Radio waves (Q) X-rays (R) Gamma rays (S) Infrared\nColumn-II: (1) Radioactive nuclei (2) Vibration of atoms/molecules (3) Accelerating electrons striking metal target (4) Oscillating electric circuits", "explanation": "P→4: Radio waves are produced by oscillating charges in LC circuits and antennas. Q→3: X-rays are produced when high-speed electrons decelerate upon hitting a metal target (Bremsstrahlung). R→1: Gamma rays originate from nuclear transitions in radioactive decay. S→2: Infrared radiation is emitted by vibrating atoms and molecules (thermal motion).", "correct_answer": "B", "concept_tags": ["sources", "matching", "spectrum-production"], "payload": {"question_id": "cuet-phy-emwave-45", "subtopic": "sources of different EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "P→1, Q→3, R→4, S→2", "is_correct": false}, {"key": "B", "text": "P→4, Q→3, R→1, S→2", "is_correct": true}, {"key": "C", "text": "P→4, Q→1, R→3, S→2", "is_correct": false}, {"key": "D", "text": "P→2, Q→3, R→1, S→4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P→1 means radio waves from radioactive nuclei — incorrect. Nuclear decay produces gamma rays, not radio waves.", "misconception": "Confusing nuclear radiation with radio transmission"}, {"option_key": "C", "hint": "Q→1 implies X-rays from radioactive nuclei. While some nuclei emit X-rays, the primary source is electron deceleration in X-ray tubes (3).", "misconception": "Confusing gamma emission with X-ray production"}, {"option_key": "D", "hint": "P→2 means radio waves from atomic vibrations — incorrect. Atomic vibrations produce infrared, not radio waves.", "misconception": "Confusing thermal radiation with radio waves"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following electromagnetic waves (Column-I) with their approximate frequency ranges (Column-II):\n\nColumn-I: (P) Microwaves (Q) Visible light (R) Ultraviolet (S) X-rays\nColumn-II: (1) 10¹⁵ to 10¹⁷ Hz (2) 4 × 10¹⁴ to 7.5 × 10¹⁴ Hz (3) 10⁹ to 10¹² Hz (4) 10¹⁷ to 10²⁰ Hz", "explanation": "P→3: Microwaves have frequencies from ~10⁹ to 10¹² Hz (GHz range). Q→2: Visible light spans ~4 × 10¹⁴ Hz (red) to ~7.5 × 10¹⁴ Hz (violet). R→1: UV radiation spans ~10¹⁵ to 10¹⁷ Hz. S→4: X-rays have frequencies from ~10¹⁷ to 10²⁰ Hz.", "correct_answer": "A", "concept_tags": ["frequency-ranges", "spectrum-ordering", "matching"], "payload": {"question_id": "cuet-phy-emwave-46", "subtopic": "frequency ranges of EM spectrum", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "P→3, Q→2, R→1, S→4", "is_correct": true}, {"key": "B", "text": "P→3, Q→1, R→2, S→4", "is_correct": false}, {"key": "C", "text": "P→2, Q→3, R→1, S→4", "is_correct": false}, {"key": "D", "text": "P→3, Q→2, R→4, S→1", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Q→1 assigns 10¹⁵–10¹⁷ Hz to visible light, which is actually the UV range. Visible is only ~4–7.5 × 10¹⁴ Hz.", "misconception": "Overestimating visible light frequency"}, {"option_key": "C", "hint": "P→2 assigns ~10¹⁴ Hz to microwaves. Microwaves are much lower frequency (~10⁹–10¹² Hz).", "misconception": "Confusing microwave and visible frequencies"}, {"option_key": "D", "hint": "R→4 assigns 10¹⁷–10²⁰ Hz to UV, but that''s the X-ray range. UV is lower frequency than X-rays.", "misconception": "Swapping UV and X-ray frequency ranges"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following EM wave applications (Column-I) with the type of EM wave used (Column-II):\n\nColumn-I: (P) Night vision cameras (Q) Satellite communication (R) Sterilisation of surgical instruments (S) Medical imaging of bones\nColumn-II: (1) X-rays (2) Ultraviolet (3) Microwaves (4) Infrared", "explanation": "P→4: Night vision uses infrared cameras to detect heat emitted by bodies. Q→3: Satellite communication uses microwaves which can penetrate the ionosphere. R→2: UV radiation kills bacteria and is used for sterilisation. S→1: X-rays penetrate soft tissue but are absorbed by bones, creating contrast images.", "correct_answer": "C", "concept_tags": ["applications", "matching", "practical-uses"], "payload": {"question_id": "cuet-phy-emwave-47", "subtopic": "applications of EM spectrum", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "P→4, Q→3, R→1, S→2", "is_correct": false}, {"key": "B", "text": "P→3, Q→4, R→2, S→1", "is_correct": false}, {"key": "C", "text": "P→4, Q→3, R→2, S→1", "is_correct": true}, {"key": "D", "text": "P→4, Q→2, R→3, S→1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R→1 means sterilisation with X-rays — UV is the standard sterilisation method, not X-rays.", "misconception": "Confusing X-ray imaging with UV sterilisation"}, {"option_key": "B", "hint": "P→3 means night vision with microwaves — night vision cameras detect infrared (heat), not microwaves.", "misconception": "Confusing thermal IR with microwave detection"}, {"option_key": "D", "hint": "Q→2 means satellite communication with UV — UV is absorbed by the atmosphere. Microwaves pass through.", "misconception": "Thinking UV can be used for long-range communication"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electromagnetic waves require a material medium for their propagation.", "explanation": "This statement is FALSE. Electromagnetic waves are self-sustaining oscillations of electric and magnetic fields and do NOT require a material medium. They can propagate through vacuum at the speed of light. This is fundamentally different from mechanical waves like sound, which need a medium.", "correct_answer": "B", "concept_tags": ["vacuum-propagation", "no-medium", "em-vs-mechanical"], "payload": {"question_id": "cuet-phy-emwave-48", "subtopic": "properties of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Sunlight reaches us through the vacuum of space — clear proof that EM waves don''t need a medium.", "misconception": "Confusing EM waves with sound waves which do need a medium"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "X-rays have a higher frequency than ultraviolet rays.", "explanation": "This statement is TRUE. In the EM spectrum, frequency increases as: radio < microwave < IR < visible < UV < X-rays < gamma rays. X-rays (10¹⁷–10²⁰ Hz) have higher frequency than UV (10¹⁵–10¹⁷ Hz).", "correct_answer": "A", "concept_tags": ["frequency-ordering", "x-rays-vs-uv", "spectrum"], "payload": {"question_id": "cuet-phy-emwave-49", "subtopic": "EM spectrum ordering", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "X-rays are more energetic than UV — since E = hf, higher energy means higher frequency.", "misconception": "Reversing the order of X-rays and UV in the spectrum"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "In an electromagnetic wave, the electric and magnetic fields are in phase with each other.", "explanation": "This statement is TRUE. In an EM wave, E and B reach their maximum, minimum, and zero values simultaneously — they oscillate in phase. If E = E₀ sin(kx − ωt), then B = B₀ sin(kx − ωt) with the same phase. They differ in direction (perpendicular) and magnitude (B₀ = E₀/c), but not in phase.", "correct_answer": "A", "concept_tags": ["phase-relation", "E-B-in-phase", "wave-properties"], "payload": {"question_id": "cuet-phy-emwave-50", "subtopic": "phase relationship in EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Unlike standing waves or LC oscillations where E and B are 90° out of phase, in a travelling EM wave they are always in phase.", "misconception": "Confusing travelling wave with standing wave or LC circuit phase relations"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "The displacement current between the plates of a charging capacitor is equal to the conduction current in the external circuit.", "explanation": "This statement is TRUE. Maxwell showed that the displacement current Id = ε₀(dΦE/dt) between the capacitor plates equals the conduction current Ic in the connecting wires. This ensures continuity of current through the circuit, including the gap between the capacitor plates where no charges actually flow.", "correct_answer": "A", "concept_tags": ["displacement-current", "conduction-current", "continuity"], "payload": {"question_id": "cuet-phy-emwave-51", "subtopic": "displacement current", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "If Id ≠ Ic, Kirchhoff''s current law would be violated at the capacitor terminals. Maxwell''s correction precisely ensures Id = Ic.", "misconception": "Thinking current is discontinuous at capacitor plates"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The part of the electromagnetic spectrum used in television remote controls is ______.", "explanation": "Television remote controls use infrared (IR) radiation. They emit IR light pulses in coded patterns that are received by an IR sensor on the TV. IR is used because it is invisible, safe, low-power, and works well over short distances within a room.", "correct_answer": "C", "concept_tags": ["infrared", "remote-control", "applications"], "payload": {"question_id": "cuet-phy-emwave-52", "subtopic": "everyday applications of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Radio waves", "is_correct": false}, {"key": "B", "text": "Microwaves", "is_correct": false}, {"key": "C", "text": "Infrared", "is_correct": true}, {"key": "D", "text": "Ultraviolet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Radio waves are used for broadcast communication (FM/AM radio, WiFi), not for TV remote controls.", "misconception": "Confusing radio broadcast with remote control"}, {"option_key": "B", "hint": "Microwaves are used in ovens and long-distance communication, not in handheld remote controls.", "misconception": "Confusing different wireless technologies"}, {"option_key": "D", "hint": "UV radiation can be harmful to eyes and skin. It would be unsafe and impractical for a consumer remote control.", "misconception": "Thinking any invisible radiation works for remotes"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "Maxwell added ______ current to Ampere''s circuital law to make it consistent for both steady and time-varying fields.", "explanation": "Maxwell added the displacement current (Id = ε₀ dΦE/dt) to Ampere''s circuital law. The original law worked for steady currents but failed for time-varying fields (e.g., between capacitor plates during charging). The modified law is: ∮B·dl = μ₀(Ic + Id), where Ic is conduction current and Id is displacement current.", "correct_answer": "B", "concept_tags": ["displacement-current", "ampere-law", "maxwell-correction"], "payload": {"question_id": "cuet-phy-emwave-53", "subtopic": "Maxwell''s modification of Ampere''s law", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Conduction", "is_correct": false}, {"key": "B", "text": "Displacement", "is_correct": true}, {"key": "C", "text": "Convection", "is_correct": false}, {"key": "D", "text": "Eddy", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Conduction current was already in the original Ampere''s law. Maxwell added something new, not what was already there.", "misconception": "Confusing existing term with the new addition"}, {"option_key": "C", "hint": "Convection current refers to charge transport in fluids. It is not related to Maxwell''s theoretical correction.", "misconception": "Random guess among current types"}, {"option_key": "D", "hint": "Eddy currents are induced circular currents in conductors, related to Faraday''s law — not Maxwell''s correction to Ampere''s law.", "misconception": "Confusing Faraday''s law effects with Maxwell''s addition"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The speed of light in vacuum, c = 1/√(μ₀ε₀), has a value of approximately ______ m/s.", "explanation": "Using μ₀ = 4π × 10⁻⁷ H/m and ε₀ = 8.854 × 10⁻¹² F/m, c = 1/√(μ₀ε₀) = 1/√(4π × 10⁻⁷ × 8.854 × 10⁻¹²) ≈ 3 × 10⁸ m/s. This value was calculated by Maxwell and matched the experimentally known speed of light, leading him to conclude that light is an electromagnetic wave.", "correct_answer": "A", "concept_tags": ["speed-of-light", "mu-epsilon", "maxwell-prediction"], "payload": {"question_id": "cuet-phy-emwave-54", "subtopic": "derivation of speed of light", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "3 × 10⁸", "is_correct": true}, {"key": "B", "text": "3 × 10⁶", "is_correct": false}, {"key": "C", "text": "3 × 10¹⁰", "is_correct": false}, {"key": "D", "text": "3 × 10⁵", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "3 × 10⁶ m/s is about 1% of the speed of light. Light travels ~300,000 km/s, not 3,000 km/s.", "misconception": "Off by a factor of 100"}, {"option_key": "C", "hint": "3 × 10¹⁰ m/s exceeds the speed of light by 100×. Nothing can travel this fast according to relativity.", "misconception": "Confusing with c in cm/s (3 × 10¹⁰ cm/s)"}, {"option_key": "D", "hint": "3 × 10⁵ m/s is approximately the speed of sound in some metals, not the speed of light.", "misconception": "Off by three orders of magnitude"}]}}]'::jsonb, 'deploy-2026-03-05-b07');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A student is studying the electromagnetic spectrum and notes the following observations:\n(i) A TV remote works by emitting invisible radiation detected by a sensor on the TV.\n(ii) Mobile phones use radiation that can pass through walls but has less energy than light.\n(iii) Hospital X-ray machines can see through skin but not through bones.\n\nWhich of the following correctly identifies all three types of radiation?", "explanation": "(i) TV remotes use infrared radiation — invisible, low energy, short range. (ii) Mobile phones use microwaves — they can penetrate walls, have lower frequency (hence lower energy) than visible light. (iii) X-rays penetrate soft tissue but are absorbed by dense bone, creating contrast images. The correct identification is IR, Microwaves, X-rays.", "correct_answer": "B", "concept_tags": ["spectrum-identification", "real-world", "scenario"], "payload": {"question_id": "cuet-phy-emwave-55", "subtopic": "identifying EM waves from properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "(i) UV, (ii) Radio waves, (iii) X-rays", "is_correct": false}, {"key": "B", "text": "(i) Infrared, (ii) Microwaves, (iii) X-rays", "is_correct": true}, {"key": "C", "text": "(i) Infrared, (ii) Radio waves, (iii) Gamma rays", "is_correct": false}, {"key": "D", "text": "(i) Radio waves, (ii) Microwaves, (iii) X-rays", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "UV is not used in TV remotes — it would be harmful to emit UV radiation directly at people. Remotes use safe infrared.", "misconception": "Confusing invisible UV with invisible IR"}, {"option_key": "C", "hint": "Mobile phones use microwaves (GHz range), not radio waves (MHz range). Also, hospital imaging uses X-rays, not gamma rays.", "misconception": "Confusing microwave with radio, and X-ray with gamma"}, {"option_key": "D", "hint": "TV remotes emit infrared, not radio waves. Radio waves have much longer wavelengths and are used for broadcasting.", "misconception": "Thinking any wireless device uses radio waves"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A parallel plate capacitor with plate area A = 2 × 10⁻² m² is being charged by a current of 0.5 A. The electric field between the plates changes uniformly.\n\nThe displacement current between the plates is:", "explanation": "The displacement current Id between capacitor plates equals the conduction current Ic in the external circuit (Maxwell''s continuity principle). Since Ic = 0.5 A, Id = 0.5 A. This can be verified: Id = ε₀(dΦE/dt) = ε₀A(dE/dt). Since the charging current provides dQ/dt = 0.5 A, and Q = ε₀AE, we get ε₀A(dE/dt) = dQ/dt = 0.5 A.", "correct_answer": "B", "concept_tags": ["displacement-current-calculation", "capacitor-charging", "maxwell"], "payload": {"question_id": "cuet-phy-emwave-56", "subtopic": "displacement current numerical", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "0.25 A", "is_correct": false}, {"key": "B", "text": "0.5 A", "is_correct": true}, {"key": "C", "text": "1.0 A", "is_correct": false}, {"key": "D", "text": "Depends on the plate area", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Id = Ic always (for a charging capacitor). The displacement current is NOT half the conduction current.", "misconception": "Thinking displacement current is half of conduction current"}, {"option_key": "C", "hint": "Id = Ic = 0.5 A, not 2 × Ic. There is no doubling factor in the Id-Ic relationship.", "misconception": "Doubling the current incorrectly"}, {"option_key": "D", "hint": "While ε₀A(dE/dt) depends on area, the result always equals Ic regardless of plate dimensions. The area cancels out.", "misconception": "Thinking displacement current depends on plate geometry independently of conduction current"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "An astronaut on the International Space Station communicates with ground control using radio signals. The ISS orbits at a height of approximately 400 km above Earth''s surface.\n\nThe time delay for the radio signal to travel from ISS to Earth is approximately:", "explanation": "Radio signals travel at the speed of light, c = 3 × 10⁸ m/s. Distance = 400 km = 4 × 10⁵ m. Time = distance/speed = 4 × 10⁵/(3 × 10⁸) = 1.33 × 10⁻³ s ≈ 1.3 ms. This is barely perceptible in conversation.", "correct_answer": "B", "concept_tags": ["speed-distance-time", "space-communication", "practical"], "payload": {"question_id": "cuet-phy-emwave-57", "subtopic": "EM wave speed applications", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "0.13 ms", "is_correct": false}, {"key": "B", "text": "1.3 ms", "is_correct": true}, {"key": "C", "text": "13 ms", "is_correct": false}, {"key": "D", "text": "1.3 s", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.13 ms corresponds to only 40 km distance, not 400 km. Check the exponent calculation.", "misconception": "Error in power of ten"}, {"option_key": "C", "hint": "13 ms corresponds to ~4000 km, which is 10× the actual ISS height.", "misconception": "Using 4 × 10⁶ m instead of 4 × 10⁵ m"}, {"option_key": "D", "hint": "1.3 s would mean a distance of ~400,000 km — roughly the Earth-Moon distance, not ISS height.", "misconception": "Major order of magnitude error"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A plane EM wave has an electric field amplitude of 480 V/m. The magnetic field amplitude and the average intensity of the wave are respectively:", "explanation": "B₀ = E₀/c = 480/(3 × 10⁸) = 1.6 × 10⁻⁶ T. Average intensity I = ½ε₀cE₀² = ½ × 8.85 × 10⁻¹² × 3 × 10⁸ × (480)² = ½ × 8.85 × 10⁻¹² × 3 × 10⁸ × 2.304 × 10⁵ = ½ × 611.5 ≈ 306 W/m².", "correct_answer": "A", "concept_tags": ["numerical", "B-amplitude", "intensity-calculation"], "payload": {"question_id": "cuet-phy-emwave-58", "subtopic": "E, B amplitude and intensity", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "1.6 × 10⁻⁶ T, 306 W/m²", "is_correct": true}, {"key": "B", "text": "1.6 × 10⁻⁶ T, 612 W/m²", "is_correct": false}, {"key": "C", "text": "1.6 × 10⁻⁸ T, 306 W/m²", "is_correct": false}, {"key": "D", "text": "1.6 × 10⁻⁶ T, 153 W/m²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "612 W/m² is the peak intensity (ε₀cE₀²), not the average. For average, you need the ½ factor from time-averaging sin².", "misconception": "Forgetting the ½ factor in average intensity"}, {"option_key": "C", "hint": "1.6 × 10⁻⁸ T is 100× too small. B₀ = E₀/c = 480/(3×10⁸) = 1.6 × 10⁻⁶ T.", "misconception": "Arithmetic error in exponents: 10⁰/10⁸ ≠ 10⁻⁸ for this calculation"}, {"option_key": "D", "hint": "153 W/m² is ¼ε₀cE₀², which counts only the electric field contribution. Total intensity includes both E and B.", "misconception": "Forgetting to add the magnetic field energy contribution"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which property of electromagnetic waves proves that they are transverse?", "explanation": "Polarisation is exclusively a property of transverse waves. Only waves whose oscillations are perpendicular to the propagation direction can be polarised (restricted to a single plane). Longitudinal waves like sound cannot be polarised. The fact that light can be polarised (using Polaroid filters, for example) proves it is transverse.", "correct_answer": "C", "concept_tags": ["polarisation", "transverse-proof", "wave-nature"], "payload": {"question_id": "cuet-phy-emwave-59", "subtopic": "evidence for transverse nature", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Reflection", "is_correct": false}, {"key": "B", "text": "Diffraction", "is_correct": false}, {"key": "C", "text": "Polarisation", "is_correct": true}, {"key": "D", "text": "Interference", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Both transverse and longitudinal waves can be reflected. Reflection doesn''t distinguish wave type.", "misconception": "Thinking reflection is unique to transverse waves"}, {"option_key": "B", "hint": "Diffraction occurs for all types of waves — it proves wave nature but not transverse nature.", "misconception": "Confusing wave nature with transverse nature"}, {"option_key": "D", "hint": "Interference occurs for both longitudinal and transverse waves (e.g., sound interference). It proves wave nature, not transverse nature.", "misconception": "Confusing general wave properties with transverse-specific properties"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electric field of a sinusoidal EM wave in vacuum obeys the equation E = 100 sin(5 × 10⁶ t − kx) V/m. The wavelength of the wave is:", "explanation": "From the equation, ω = 5 × 10⁶ rad/s. Frequency f = ω/(2π) = 5 × 10⁶/(2π) Hz. Using c = fλ, we get λ = c/f = 2πc/ω = 2π × 3 × 10⁸/(5 × 10⁶) = 6π × 10⁸/5 × 10⁶ = 6π × 10² ≈ 120π m ≈ 377 m. Alternatively, k = ω/c = 5 × 10⁶/(3 × 10⁸) = 1.67 × 10⁻² rad/m, and λ = 2π/k = 2π/(1.67 × 10⁻²) ≈ 376.8 m.", "correct_answer": "D", "concept_tags": ["wave-equation", "wavelength-from-omega", "numerical"], "payload": {"question_id": "cuet-phy-emwave-60", "subtopic": "EM wave equation analysis", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "60 m", "is_correct": false}, {"key": "B", "text": "60π m", "is_correct": false}, {"key": "C", "text": "12π m", "is_correct": false}, {"key": "D", "text": "120π m", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "60 m forgets the 2π factor. λ = 2πc/ω, not c/ω.", "misconception": "Using λ = c/ω instead of λ = 2πc/ω"}, {"option_key": "B", "hint": "60π m uses λ = πc/ω. The correct formula is λ = 2πc/ω = 2π × 3 × 10⁸/(5 × 10⁶).", "misconception": "Using π instead of 2π"}, {"option_key": "C", "hint": "12π m comes from an error in the power of ten: 10⁸/10⁶ = 10² = 100, not 10.", "misconception": "Arithmetic error in exponent subtraction"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A long straight wire carries a current of 10 A. The magnetic field at a perpendicular distance of 0.1 m from the wire is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a long straight conductor, B = μ₀I/(2πd) = (4π × 10⁻⁷ × 10)/(2π × 0.1) = (4π × 10⁻⁶)/(0.2π) = 2 × 10⁻⁵ T = 20 μT.", "correct_answer": "C", "concept_tags": ["straight-conductor", "magnetic-field", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-biot-01", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "2 × 10⁻⁶ T", "is_correct": false}, {"key": "B", "text": "2 × 10⁻⁴ T", "is_correct": false}, {"key": "C", "text": "2 × 10⁻⁵ T", "is_correct": true}, {"key": "D", "text": "2 × 10⁻⁷ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is off by a factor of 10. Recheck the calculation: μ₀I/(2πd) = (4π × 10⁻⁷ × 10)/(2π × 0.1) = 2 × 10⁻⁵ T.", "misconception": "Arithmetic error with powers of 10"}, {"option_key": "B", "hint": "This is 100 times too large. The denominator 2πd = 2π × 0.1 ≈ 0.628, and dividing 4π × 10⁻⁶ by this gives 2 × 10⁻⁵, not 2 × 10⁻⁴.", "misconception": "Error in handling decimal distance"}, {"option_key": "D", "hint": "This equals μ₀/2π, which would correspond to I = 1 A at d = 1 m. With I = 10 A and d = 0.1 m, the field is much larger.", "misconception": "Using default values instead of given values"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Ampere''s circuital law states that the line integral of magnetic field B around a closed loop equals:", "explanation": "Ampere''s circuital law states ∮B·dl = μ₀I_enclosed, where I_enclosed is the total current threading through the closed Amperian loop. This law is analogous to Gauss''s law in electrostatics and is most useful when the magnetic field has high symmetry.", "correct_answer": "D", "concept_tags": ["ampere-law", "line-integral", "enclosed-current"], "payload": {"question_id": "cuet-phy-mag-biot-02", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀ times the total current in the circuit", "is_correct": false}, {"key": "B", "text": "The total magnetic flux through the loop", "is_correct": false}, {"key": "C", "text": "μ₀ε₀ times the rate of change of electric flux", "is_correct": false}, {"key": "D", "text": "μ₀ times the net current enclosed by the loop", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Ampere''s law considers only the current enclosed by (threading through) the Amperian loop, not the total current in the entire circuit.", "misconception": "Confusing enclosed current with total circuit current"}, {"option_key": "B", "hint": "The line integral ∮B·dl gives μ₀I_enclosed, not magnetic flux. Magnetic flux is the surface integral ∫B·dA.", "misconception": "Confusing line integral of B with surface integral of B"}, {"option_key": "C", "hint": "This is Maxwell''s displacement current term, which is an addition to Ampere''s law. The basic Ampere''s circuital law relates ∮B·dl to μ₀I_enclosed.", "misconception": "Confusing Ampere''s law with Maxwell''s modification"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In the Biot-Savart law, dB = (μ₀/4π)(Idl × r̂)/r², the direction of the magnetic field dB at a point is determined by:", "explanation": "In the Biot-Savart law, the magnetic field dB is given by the cross product Idl × r̂. The direction of this cross product is perpendicular to the plane containing the current element dl and the position vector r̂. This direction is found using the right-hand rule: curl the fingers from dl toward r̂, and the thumb points in the direction of dB.", "correct_answer": "A", "concept_tags": ["biot-savart-law", "cross-product", "right-hand-rule"], "payload": {"question_id": "cuet-phy-mag-biot-03", "subtopic": "Biot-Savart law vector form", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "The cross product dl × r̂, perpendicular to the plane of dl and r̂", "is_correct": true}, {"key": "B", "text": "The dot product dl · r̂, along the current element", "is_correct": false}, {"key": "C", "text": "Along the position vector r̂ joining the element to the point", "is_correct": false}, {"key": "D", "text": "Along the current element dl itself", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The dot product gives a scalar, not a vector direction. Biot-Savart law involves a cross product.", "misconception": "Confusing dot product with cross product in the Biot-Savart law"}, {"option_key": "C", "hint": "The magnetic field is perpendicular to r̂, not along it. This would describe an electric field direction.", "misconception": "Confusing magnetic field direction with electric field direction"}, {"option_key": "D", "hint": "dB is perpendicular to dl, not along it. A field along dl would violate the cross-product nature of the law.", "misconception": "Thinking the magnetic field is along the current direction"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field at a perpendicular distance d from an infinitely long straight wire carrying current I is given by B = μ₀I/(2πd). If the current is doubled and the distance is halved, the new magnetic field becomes:", "explanation": "The magnetic field due to an infinite straight wire is B = μ₀I/(2πd). When current is doubled (I → 2I) and distance is halved (d → d/2), the new field B'' = μ₀(2I)/(2π × d/2) = μ₀(2I) × 2/(2πd) = 4 × μ₀I/(2πd) = 4B. The field becomes four times the original value.", "correct_answer": "B", "concept_tags": ["infinite-wire", "magnetic-field-proportionality", "inverse-distance"], "payload": {"question_id": "cuet-phy-mag-biot-04", "subtopic": "Infinite straight wire", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "2B", "is_correct": false}, {"key": "B", "text": "4B", "is_correct": true}, {"key": "C", "text": "B", "is_correct": false}, {"key": "D", "text": "8B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This only accounts for the doubling of current but ignores the effect of halving the distance.", "misconception": "Forgetting that B is inversely proportional to distance"}, {"option_key": "C", "hint": "Both current and distance changed, so the field cannot remain the same.", "misconception": "Thinking the effects of current and distance cancel out"}, {"option_key": "D", "hint": "B is proportional to I/d, not I/d². Halving d gives a factor of 2, not 4.", "misconception": "Confusing inverse-distance with inverse-square dependence"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Biot-Savart law, the magnetic field dB due to a small current element Idl at a point P is proportional to:", "explanation": "The Biot-Savart law states dB = (μ₀/4π)(Idl × r̂)/r². The magnitude of dB is proportional to sinθ (from the cross product) and inversely proportional to r². Here θ is the angle between the current element dl and the position vector r pointing from the element to the point P.", "correct_answer": "A", "concept_tags": ["biot-savart-law", "magnetic-field", "current-element"], "payload": {"question_id": "cuet-phy-mag-biot-05", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "sinθ/r², where θ is the angle between dl and r", "is_correct": true}, {"key": "B", "text": "cosθ/r², where θ is the angle between dl and r", "is_correct": false}, {"key": "C", "text": "sinθ/r, where θ is the angle between dl and r", "is_correct": false}, {"key": "D", "text": "cosθ/r, where θ is the angle between dl and r", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Biot-Savart law involves a cross product (Idl × r̂), which gives sinθ, not cosθ. The cosθ dependence appears in electrostatics (e.g., electric flux), not here.", "misconception": "Confusing cross product with dot product"}, {"option_key": "C", "hint": "The field falls off as 1/r², not 1/r. The inverse-square dependence is analogous to Coulomb''s law.", "misconception": "Incorrect distance dependence"}, {"option_key": "D", "hint": "This has both the wrong angular dependence (cosθ instead of sinθ) and the wrong distance dependence (1/r instead of 1/r²).", "misconception": "Multiple errors in Biot-Savart law recall"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field at the centre of a circular loop of radius R carrying current I is:", "explanation": "Using the Biot-Savart law and integrating over the entire circular loop, every element dl is perpendicular to the position vector r (θ = 90°) and at a distance R from the centre. The integration gives B = μ₀I/(2R). This is a standard result frequently used in NEET problems.", "correct_answer": "B", "concept_tags": ["circular-loop", "magnetic-field-centre", "biot-savart-law"], "payload": {"question_id": "cuet-phy-mag-biot-06", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀I/(4πR)", "is_correct": false}, {"key": "B", "text": "μ₀I/(2R)", "is_correct": true}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀IR²/2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(4πR) would result from integrating only a quarter of the loop. The full circular loop gives μ₀I/(2R).", "misconception": "Incomplete integration of the loop"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the magnetic field due to a long straight conductor at perpendicular distance R, not at the centre of a circular loop.", "misconception": "Confusing straight wire formula with circular loop formula"}, {"option_key": "D", "hint": "This expression has incorrect dimensions. μ₀IR²/2 has units of T·m³, not Tesla. The correct formula is μ₀I/(2R).", "misconception": "Dimensional error in the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A straight conductor of length L carries a current I. The magnetic field at a point on the perpendicular bisector at a distance d from the conductor is B = (μ₀I/4πd)(2sinα), where α is the half-angle subtended by the conductor. As L → ∞, this expression reduces to:", "explanation": "For a finite straight conductor, B = (μ₀I/4πd)(sinα₁ + sinα₂). On the perpendicular bisector, α₁ = α₂ = α, so B = (μ₀I/4πd)(2sinα). As L → ∞, α → 90°, so sinα → 1. Therefore B = (μ₀I/4πd)(2) = μ₀I/(2πd), which is the well-known result for an infinite straight wire.", "correct_answer": "C", "concept_tags": ["finite-conductor", "infinite-wire-limit", "perpendicular-bisector"], "payload": {"question_id": "cuet-phy-mag-biot-07", "subtopic": "Magnetic field due to straight conductor", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "μ₀I/(4πd)", "is_correct": false}, {"key": "B", "text": "μ₀I/(πd)", "is_correct": false}, {"key": "C", "text": "μ₀I/(2πd)", "is_correct": true}, {"key": "D", "text": "μ₀I/(4πd²)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is missing the factor of 2 that comes from both halves of the infinite wire contributing equally.", "misconception": "Forgetting the limiting value of 2sinα as L → ∞"}, {"option_key": "B", "hint": "This is twice the correct answer. Check the algebra when substituting sinα = 1.", "misconception": "Arithmetic error in simplification"}, {"option_key": "D", "hint": "The field of a straight wire depends on 1/d, not 1/d². The inverse-square dependence is for point sources.", "misconception": "Confusing with Coulomb''s law distance dependence"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two parallel infinite wires separated by distance a carry currents I₁ and I₂ in the same direction. The magnetic field at a point midway between them is:", "explanation": "At the midpoint, the distance from each wire is a/2. Wire 1 produces B₁ = μ₀I₁/(2π × a/2) = μ₀I₁/(πa) directed (say) into the page. Wire 2 produces B₂ = μ₀I₂/(2π × a/2) = μ₀I₂/(πa) directed out of the page (by right-hand rule, since currents are in the same direction, the fields at the midpoint are in opposite directions). The net field is B = μ₀(I₁ − I₂)/(πa). When I₁ = I₂, the net field is zero.", "correct_answer": "D", "concept_tags": ["superposition", "parallel-wires", "right-hand-rule"], "payload": {"question_id": "cuet-phy-mag-biot-08", "subtopic": "Superposition of magnetic fields", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "μ₀(I₁ + I₂)/(πa), always additive", "is_correct": false}, {"key": "B", "text": "Zero, regardless of the values of I₁ and I₂", "is_correct": false}, {"key": "C", "text": "μ₀I₁I₂/(πa²), proportional to the product of currents", "is_correct": false}, {"key": "D", "text": "μ₀(I₁ − I₂)/(πa), and zero when I₁ = I₂", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "For same-direction currents, the fields at the midpoint oppose each other, not add.", "misconception": "Ignoring direction of magnetic field when applying superposition"}, {"option_key": "B", "hint": "The field is zero only when I₁ = I₂. For unequal currents, there is a net field.", "misconception": "Assuming cancellation without checking current magnitudes"}, {"option_key": "C", "hint": "Magnetic field uses superposition (addition/subtraction of B), not multiplication of currents.", "misconception": "Confusing force between wires with field superposition"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at the centre of a circular coil of radius R carrying current I is B₀. The magnetic field on the axis of the same coil at a distance R from the centre is:", "explanation": "The field at the centre is B₀ = μ₀I/(2R). The field on the axis at distance x from the centre is B = (μ₀IR²)/(2(R² + x²)^(3/2)). At x = R: B = (μ₀IR²)/(2(R² + R²)^(3/2)) = (μ₀IR²)/(2(2R²)^(3/2)) = (μ₀IR²)/(2 × 2√2 × R³) = μ₀I/(4√2 R) = B₀/(2√2). This can also be written as B₀√2/4.", "correct_answer": "C", "concept_tags": ["circular-loop-axis", "axial-field", "distance-dependence"], "payload": {"question_id": "cuet-phy-mag-biot-09", "subtopic": "Magnetic field due to circular loop on axis", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "B₀/2", "is_correct": false}, {"key": "B", "text": "B₀/4", "is_correct": false}, {"key": "C", "text": "B₀/(2√2)", "is_correct": true}, {"key": "D", "text": "B₀/√2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This ignores the (R² + x²)^(3/2) factor in the denominator. The decay is not simply 1/2 at x = R.", "misconception": "Assuming linear decay of field along axis"}, {"option_key": "B", "hint": "Check the power of (2R²)^(3/2). It equals 2√2 R³, not 4R³.", "misconception": "Error in evaluating (2)^(3/2)"}, {"option_key": "D", "hint": "This would require (R² + x²)^(3/2) = √2 R³, which is not correct for x = R.", "misconception": "Algebraic error in the axial field formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of length 0.5 m has 1000 turns and carries a current of 2 A. The magnetic field inside the solenoid is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a solenoid, B = μ₀nI where n = N/L = 1000/0.5 = 2000 turns/m. B = 4π × 10⁻⁷ × 2000 × 2 = 4π × 10⁻⁷ × 4000 = 16π × 10⁻⁴ = 16 × 3.14 × 10⁻⁴ ≈ 5.03 × 10⁻³ T ≈ 5.03 mT.", "correct_answer": "C", "concept_tags": ["solenoid", "ampere-law", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-biot-10", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "2.51 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "1.26 × 10⁻³ T", "is_correct": false}, {"key": "C", "text": "5.03 × 10⁻³ T", "is_correct": true}, {"key": "D", "text": "5.03 × 10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is exactly half the correct answer, suggesting you used N = 1000 instead of n = N/L = 2000 turns/m, or missed the current value.", "misconception": "Using total turns instead of turns per unit length"}, {"option_key": "B", "hint": "This would correspond to n = 1000 and I = 1, indicating errors in both n and I. Use n = N/L = 2000 turns/m and I = 2 A.", "misconception": "Multiple calculation errors"}, {"option_key": "D", "hint": "This is off by a factor of 10. Check the power of 10 in your calculation: μ₀nI = 4π × 10⁻⁷ × 2000 × 2 = 16π × 10⁻⁴ ≈ 5.03 × 10⁻³.", "misconception": "Power of 10 arithmetic error"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at the centre of a quarter-circle arc of radius R carrying current I is:", "explanation": "A quarter-circle arc subtends an angle π/2 at the centre. Using the formula B = μ₀Iφ/(4πR) for an arc of angle φ: B = μ₀I(π/2)/(4πR) = μ₀I/(8R). The straight portions (if connected along radii) contribute zero field at the centre because the current element is parallel to the position vector (sin0° = 0).", "correct_answer": "D", "concept_tags": ["quarter-arc", "magnetic-field", "biot-savart-law"], "payload": {"question_id": "cuet-phy-mag-biot-11", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(2R)", "is_correct": false}, {"key": "B", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀I/(8R)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(2R) is the field at the centre of a full circular loop. A quarter arc is one-fourth of the loop, giving μ₀I/(8R).", "misconception": "Using full loop formula for quarter arc"}, {"option_key": "B", "hint": "μ₀I/(4R) is the field due to a semicircular arc (half loop). A quarter arc gives half of this value: μ₀I/(8R).", "misconception": "Confusing semicircle with quarter circle"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the field of a long straight wire at distance R. The arc formula uses the angle subtended, not the straight-wire formula.", "misconception": "Applying straight wire formula to a curved conductor"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A comparison between Biot-Savart law and Coulomb''s law shows that both:", "explanation": "Both the Biot-Savart law (dB = μ₀Idl×r̂/(4πr²)) and Coulomb''s law (E = q r̂/(4πε₀r²)) exhibit an inverse-square dependence on distance. However, the Biot-Savart law involves a cross product (giving an angular dependence and a field perpendicular to the plane of dl and r), while Coulomb''s law produces a field along the line joining the source and point. Both also have a similar constant structure: μ₀/4π in Biot-Savart and 1/4πε₀ in Coulomb''s law.", "correct_answer": "D", "concept_tags": ["biot-savart-law", "coulomb-law", "comparison", "inverse-square"], "payload": {"question_id": "cuet-phy-mag-biot-12", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "Produce fields along the line joining source and field point", "is_correct": false}, {"key": "B", "text": "Are valid only for static charges", "is_correct": false}, {"key": "C", "text": "Involve a dot product between source vector and displacement", "is_correct": false}, {"key": "D", "text": "Obey the inverse-square law of distance dependence", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s law gives a field along the line joining source and point, but Biot-Savart law gives a field perpendicular to the plane containing dl and r (due to the cross product).", "misconception": "Assuming both laws give fields in the same direction relative to source"}, {"option_key": "B", "hint": "Biot-Savart law deals with moving charges (current), not static charges. Coulomb''s law is for static charges. They are not both valid for the same scenario.", "misconception": "Confusing the domain of applicability of the two laws"}, {"option_key": "C", "hint": "Biot-Savart law involves a cross product (dl × r̂), not a dot product. This is a key difference from Coulomb''s law.", "misconception": "Confusing cross product with dot product in Biot-Savart law"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A wire carrying current I is bent into a circular arc of radius R subtending an angle of 60° at its centre. The magnitude of the magnetic field at the centre of the arc is:", "explanation": "The magnetic field at the centre of a circular arc subtending angle θ (in radians) is B = (μ₀I/2R)(θ/2π). For a 60° arc, θ = π/3 radians. Therefore B = (μ₀I/2R)(π/3)/(2π) = (μ₀I/2R)(1/6) = μ₀I/(12R).", "correct_answer": "A", "concept_tags": ["circular-arc", "magnetic-field-centre", "angle-subtended"], "payload": {"question_id": "cuet-phy-mag-biot-13", "subtopic": "Magnetic field at centre of arc/semicircle", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(12R)", "is_correct": true}, {"key": "B", "text": "μ₀I/(6R)", "is_correct": false}, {"key": "C", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "D", "text": "μ₀I/(2R)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This would be for a 120° arc (one-third of a full circle), not 60°.", "misconception": "Incorrectly computing the fraction of the circle"}, {"option_key": "C", "hint": "This is for a semicircular arc (180°), not 60°.", "misconception": "Confusing a 60° arc with a semicircle"}, {"option_key": "D", "hint": "This is for a full circular loop (360°). A 60° arc is only 1/6 of the full circle.", "misconception": "Using the full-loop formula without scaling by the arc fraction"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A circular loop of radius 0.1 m carries a current of 5 A. The magnetic field on the axis of the loop at a distance of 0.1 m from the centre is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "Using B = μ₀IR²/[2(R² + x²)^(3/2)] with R = 0.1 m, x = 0.1 m, I = 5 A: R² + x² = 0.01 + 0.01 = 0.02, so (R² + x²)^(3/2) = (0.02)^(3/2) = (0.02)^1 × √0.02 = 0.02 × 0.1414 = 2.828 × 10⁻³. Then B = (4π × 10⁻⁷ × 5 × 0.01)/(2 × 2.828 × 10⁻³) = (2π × 10⁻⁸)/(5.656 × 10⁻³) = 6.28 × 10⁻⁸/5.656 × 10⁻³ ≈ 1.11 × 10⁻⁵ T ≈ 11.1 μT.", "correct_answer": "A", "concept_tags": ["circular-loop", "axial-field", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-biot-14", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "1.11 × 10⁻⁵ T", "is_correct": true}, {"key": "B", "text": "3.14 × 10⁻⁵ T", "is_correct": false}, {"key": "C", "text": "2.22 × 10⁻⁵ T", "is_correct": false}, {"key": "D", "text": "5.55 × 10⁻⁶ T", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the value of μ₀I/(2R) = the field at the centre. At x = R on the axis, the field is reduced by a factor of 1/(2√2) compared to the centre field.", "misconception": "Using centre formula instead of axial formula"}, {"option_key": "C", "hint": "This is exactly double the correct answer. Check the factor of 2 in the denominator of B = μ₀IR²/[2(R² + x²)^(3/2)].", "misconception": "Missing the factor of 2 in the denominator"}, {"option_key": "D", "hint": "This is half the correct answer. Check the evaluation of (R² + x²)^(3/2) carefully.", "misconception": "Error in computing (R² + x²)^(3/2)"}]}}]'::jsonb, 'deploy-2026-03-05-b07');

